ogic.EntityGetPos(bn)if Logic.IsBuilding(bn)==1 then C,D=Logic.GetBuildingApproachPosition(bn)end;local bp=Logic.GetPlayerSectorAtPosition(self.PlayerID,C,D)local C,D,E=Logic.EntityGetPos(bo)if Logic.IsBuilding(bo)==1 then C,D=Logic.GetBuildingApproachPosition(bo)end;local bq=Logic.GetPlayerSectorAtPosition(self.PlayerID,C,D)if bp~=bq then return true end;return nil end;function B_Goal_BuildWall:GetMsgKey()return"Quest_Create_Wall"end;function B_Goal_BuildWall:GetIcon()return{3,9}end;function B_Goal_BuildWall:Debug(b3)if not IsExisting(self.EntityName1)or not IsExisting(self.EntityName2)then debug(false,b3.Identifier..": "..self.Name..": first or second entity does not exist!")return true elseif not tonumber(self.PlayerID)or self.PlayerID<1 or self.PlayerID>8 then debug(false,b3.Identifier..": "..self.Name..": got an invalid playerID!")return true end;if GetDiplomacyState(b3.ReceivingPlayer,self.PlayerID)>-1 and not self.WarningPrinted then warn(false,b3.Identifier..": "..self.Name..": player %d is neighter enemy or unknown to quest receiver!")self.WarningPrinted=true end;return false end;RegisterBehavior(B_Goal_BuildWall)function Goal_Claim(...)return B_Goal_Claim:new(...)end;B_Goal_Claim={Name="Goal_Claim",Description={en="Goal: Claim a territory",de="Ziel: Erobere ein Territorium",fr="Objectif: Conquérir un territoire"},Parameter={{ParameterType.TerritoryName,en="Territory",de="Territorium",fr="Territoire"}}}function B_Goal_Claim:GetGoalTable()return{Objective.Claim,1,self.TerritoryID}end;function B_Goal_Claim:AddParameter(b4,b5)if b4==0 then self.TerritoryID=tonumber(b5)if not self.TerritoryID then self.TerritoryID=GetTerritoryIDByName(b5)end end end;function B_Goal_Claim:GetMsgKey()return"Quest_Claim_Territory"end;RegisterBehavior(B_Goal_Claim)function Goal_ClaimXTerritories(...)return B_Goal_ClaimXTerritories:new(...)end;B_Goal_ClaimXTerritories={Name="Goal_ClaimXTerritories",Description={en="Goal: Claim the given number of territories, all player territories 