 Variable",fr="Valeur ou variable"}}}function B_Reprisal_CustomVariables:GetReprisalTable()return{Reprisal.Custom,{self,self.CustomFunction}}end;function B_Reprisal_CustomVariables:AddParameter(b4,b5)if b4==0 then self.VariableName=b5 elseif b4==1 then self.Operator=b5 elseif b4==2 then local by=tonumber(b5)self.Value=by==nil and tostring(b5)or by end end;function B_Reprisal_CustomVariables:CustomFunction()local bz=ObtainCustomVariable("BehaviorVariable_"..self.VariableName,0)local bA=self.Value;if type(self.Value)=="string"then bA=ObtainCustomVariable("BehaviorVariable_"..self.Value,0)end;if self.Operator=="="then bz=bA elseif self.Operator=="+"then bz=bz+bA elseif self.Operator=="-"then bz=bz-bA elseif self.Operator=="*"then bz=bz*bA elseif self.Operator=="/"then bz=bz/bA elseif self.Operator=="^"then bz=bz%bA end;SaveCustomVariable("BehaviorVariable_"..self.VariableName,bz)end;function B_Reprisal_CustomVariables:GetCustomData(b4)return{"=","+","-","*","/","^"}end;function B_Reprisal_CustomVariables:Debug(b3)local bQ={"=","+","-","*","/","^"}if not table.contains(bQ,self.Operator)then debug(false,b3.Identifier..": "..self.Name..": got an invalid operator!")return true elseif self.VariableName==""then debug(false,b3.Identifier..": "..self.Name..": missing name for variable!")return true end;return false end;RegisterBehavior(B_Reprisal_CustomVariables)function Reprisal_MapScriptFunction(...)return B_Reprisal_MapScriptFunction:new(...)end;B_Reprisal_MapScriptFunction={Name="Reprisal_MapScriptFunction",Description={en="Reprisal: Calls a function within the global map script if the quest has failed.",de="Vergeltung: Ruft eine Funktion im globalen Kartenskript auf, wenn die Quest fehlschlägt.",fr="Rétribution: lance une fonction dans le script global de la carte en cas d'échec de la quête."},Parameter={{ParameterType.Default,en="Function name",de="Funktionsname",fr="Nom de la fonction"}}}function B_Reprisal_MapScriptFunction:GetReprisalTable()return{Reprisal.Custom,{sel