ry(self.UnitKey,EntityCategories.Soldier)==1 then bY=Logic.CreateBattalionOnUnblockedLand(Entities[self.UnitKey],aI.X,aI.Y,self.Orientation,self.PlayerID,1)local c5,c6=Logic.GetSoldiersAttachedToLeader(bY)Logic.SetOrientation(c6,math.floor(self.Orientation+0.5))else bY=Logic.CreateEntityOnUnblockedLand(Entities[self.UnitKey],aI.X,aI.Y,self.Orientation,self.PlayerID)end;Logic.SetEntityName(bY,self.ScriptNameEntity.."_"..f)if self.HideFromAI then AICore.HideEntityFromAI(self.PlayerID,bY,true)end end end;function B_Reward_CreateSeveralEntities:GetCustomData(b4)local b7={}if b4==3 then for g,h in pairs(Entities)do local ao={"^M_*","^XS_*","^X_*","^XT_*","^Z_*"}local bP=false;for f=1,#ao do if g:find(ao[f])then bP=true;break end end;if not bP then table.insert(b7,g)end end;table.sort(b7)elseif b4==5 or b4==6 then table.insert(b7,"false")table.insert(b7,"true")else assert(false)end;return b7 end;function B_Reward_CreateSeveralEntities:Debug(b3)if not Entities[self.UnitKey]then debug(false,b3.Identifier..": "..self.Name..": got an invalid entity type!")return true elseif not IsExisting(self.ScriptNameEntity)then debug(false,b3.Identifier..": "..self.Name..": spawnpoint does not exist!")return true elseif tonumber(self.PlayerID)==nil or self.PlayerID<1 or self.PlayerID>8 then debug(false,b3.Identifier..": "..self.Name..": spawnpoint does not exist!")return true elseif tonumber(self.Orientation)==nil then debug(false,b3.Identifier..": "..self.Name..": orientation must be a number!")return true elseif tonumber(self.Amount)==nil or self.Amount<0 then debug(false,b3.Identifier..": "..self.Name..": amount can not be negative!")return true end;return false end;RegisterBehavior(B_Reward_CreateSeveralEntities)function Reward_MoveSettler(...)return B_Reward_MoveSettler:new(...)end;B_Reward_MoveSettler={Name="Reward_MoveSettler",Description={en="Reward: Moves a (NPC) settler to a destination. Must not be AI controlled, or it won't move",de="Lohn: Bewegt einen (NPC) Siedler zu einem Zielort. Darf keinem KI Spieler gehören, ansonsten wird sich der Siedler nicht bewegen",fr="Récompense: Déplace un settler (NPC) vers une destination. Ne doit pas appartenir à un joueur IA, sinon le settler ne se déplacera pas."},Parameter={{ParameterType.ScriptName,en="Settler",de="Siedler",fr="Settler"},{ParameterType.ScriptName,en="Destination",de="Ziel",fr="Destination"}}}function B_Reward_MoveSettler:GetRewardTable()return{Reward.Custom,{self,self.CustomFunction}}end;function B_Reward_MoveSettler:AddParameter(b4,b5)if b4==0 then self.ScriptNameUnit=b5 elseif b4==1 then self.ScriptNameDest=b5 end end;function B_Reward_MoveSettler:CustomFunction(b3)if Logic.IsEntityDestroyed(self.ScriptNameUnit)or Logic.IsEntityDestroyed(self.ScriptNameDest)then return false end;local c7=GetID(self.ScriptNameDest)local c8,c9=Logic.GetEntityPosition(c7)if Logic.IsBuilding(c7)==1 then c8,c9=Logic.GetBuildingApproachPosition(c7)end;Logic.MoveSettler(GetID(self.ScriptNameUnit),c8,c9)end;function B_Reward_MoveSettler:Debug(b3)if not IsExisting(self.ScriptNameUnit)then debug(false,b3.Identifier..": "..self.Name..": mover entity does not exist!")return true elseif not IsExisting(self.ScriptNameDest)then debug(false,b3.Identifier..": "..self.Name..": destination does not exist!")return true end;return false end;RegisterBehavior(B_Reward_MoveSettler)function Reward_Victory()return B_Reward_Victory:new()end;B_Reward_Victory={Name="Reward_Victory",Description={en="Reward: The player wins the game.",de="Lohn: Der Spieler gewinnt das Spiel.",fr="Récompense: Le Joueur gagne la partie."}}function B_Reward_Victory:GetRewardTable()return{Reward.Victory}end;RegisterBehavior(B_Reward_Victory)function Reward_Defeat()return B_Reward_Defeat:new()end;B_Reward_Defeat={Name="Reward_Defeat",Description={en="Reward: The player loses the game.",de="Lohn: Der Spieler verliert das Spiel.",fr="Récompense: le Joueur perd la partie."}}function B_Reward_Defeat:GetRewardTable()return{Reward.Custom,{self,self.CustomFunction}}end;function B_Reward_Defeat:CustomFunction(b3)b3:TerminateEventsAndStuff()Logic.ExecuteInLuaLocalState("GUI_Window.MissionEndScreenSetVictoryReasonText("..g_VictoryAndDefeatType.DefeatMissionFailed..")")Defeated(b3.ReceivingPlayer)end;RegisterBehavior(B_Reward_Defeat)function Reward_FakeVictory()return B_Reward_FakeVictory:new()end;B_Reward_FakeVictory={Name="Reward_FakeVictory",Description={en="Reward: Display a victory icon for a quest",de="Lohn: Zeigt ein Siegesicon fuer diese Quest",fr="Récompense: Affiche une icône de victoire pour cette quête"}}function B_Reward_FakeVictory:GetRewardTable()return{Reward.FakeVictory}end;RegisterBehavior(B_Reward_FakeVictory)function Reward_AI_SpawnAndAttackTerritory(...)return B_Reward_AI_SpawnAndAttackTerritory:new(...)end;B_Reward_AI_SpawnAndAttackTerritory={Name="Reward_AI_SpawnAndAttackTerritory",Description={en="Reward: Spawns AI troops and attacks a territory (Hint: Use for hidden quests as a surprise)",de="Lohn: Erstellt KI Truppen und greift ein Territorium an (Tipp: Fuer eine versteckte Quest als Ueberraschung verwenden)",fr="Récompense: Créez des troupes d'IA et attaquez un territoire (astuce : utilisez une surprise pour une quête cachée)."},Parameter={{ParameterType.PlayerID,en="AI Player",de="KI Spieler",fr="Joueur AI"},{ParameterType.ScriptName,en="Spawn point",de="Erstellungsort",fr="Lieu de création"},{ParameterType.TerritoryName,en="Territory",de="Territorium",fr="Territoire"},{ParameterType.Number,en="Sword",de="Schwert",fr="Épéiste"},{ParameterType.Number,en="Bow",de="Bogen",fr="Archer"},{ParameterType.Number,en="Catapults",de="Katapulte",fr="Catapultes"},{ParameterType.Number,en="Siege towers",de="Belagerungstuerme",fr="Tours de siège"},{ParameterType.Number,en="Rams",de="Rammen",fr="Bélier"},{ParameterType.Number,en="Ammo carts",de="Munitionswagen",fr="Chariot à munitions"},{ParameterType.Custom,en="Soldier type",de="Soldatentyp",fr="Type de soldat"},{ParameterType.Custom,en="Reuse troops",de="Verwende bestehende Truppen",fr="Utiliser les troupes existantes"}}}function B_Reward_AI_SpawnAndAttackTerritory:GetRewardTable()return{Reward.Custom,{self,self.CustomFunction}}end;function B_Reward_AI_SpawnAndAttackTerritory:AddParameter(b4,b5)if b4==0 then self.AIPlayerID=b5*1 elseif b4==1 then self.Spawnpoint=b5 elseif b4==2 then self.TerritoryID=tonumber(b5)if not self.TerritoryID then self.TerritoryID=GetTerritoryIDByName(b5)end elseif b4==3 then self.NumSword=b5*1 elseif b4==4 then self.NumBow=b5*1 elseif b4==5 then self.NumCatapults=b5*1 elseif b4==6 then self.NumSiegeTowers=b5*1 elseif b4==7 then self.NumRams=b5*1 elseif b4==8 then self.NumAmmoCarts=b5*1 elseif b4==9 then if b5=="Normal"or b5==false then self.TroopType=false elseif b5=="RedPrince"or b5==true then self.TroopType=true elseif b5=="Bandit"or b5==2 then self.TroopType=2 elseif b5=="Cultist"or b5==3 then self.TroopType=3 else assert(false)end elseif b4==10 then self.ReuseTroops=ToBoolean(b5)end end;function B_Reward_AI_SpawnAndAttackTerritory:GetCustomData(b4)local b7={}if b4==9 then table.insert(b7,"Normal")table.insert(b7,"RedPrince")table.insert(b7,"Bandit")if g_GameExtraNo>=1 then table.insert(b7,"Cultist")end elseif b4==10 then table.insert(b7,"false")table.insert(b7,"true")else assert(false)end;return b7 end;function B_Reward_AI_SpawnAndAttackTerritory:CustomFunction(b3)local ca=Logic.GetTerritoryAcquiringBuildingID(self.TerritoryID)if ca~=0 then AIScript_SpawnAndAttackCity(self.AIPlayerID,ca,self.Spawnpoint,self.NumSword,self.NumBow,self.NumCatapults,self.NumSiegeTowers,self.NumRams,self.NumAmmoCarts,self.TroopType,self.ReuseTroops)end end;function B_Reward_AI_SpawnAndAttackTerritory:Debug(b3)if self.AIPlayerID<2 then debug(false,b3.Identifier..": "..self.Name..": Player "..self.AIPlayerID.." is wrong")return true elseif Logic.IsEntityDestroyed(self.Spawnpoint)then debug(false,b3.Identifier..": "..self.Name..": Entity "..self.SpawnPoint.." is missing")return true elseif self.TerritoryID==0 then debug(false,b3.Identifier..": "..self.Name..": Territory unknown")return true elseif self.NumSword<0 then debug(false,b3.Identifier..": "..self.Name..": Number of Swords is negative")return true elseif self.NumBow<0 then debug(false,b3.Identifier..": "..self.Name..": Number of Bows is negative")return true elseif self.NumBow+self.NumSword<1 then debug(false,b3.Identifier..": "..self.Name..": No Soldiers?")return true elseif self.NumCatapults<0 then debug(false,b3.Identifier..": "..self.Name..": Catapults is negative")return true elseif self.NumSiegeTowers<0 then debug(false,b3.Identifier..": "..self.Name..": SiegeTowers is negative")return true elseif self.NumRams<0 then debug(false,b3.Identifier..": "..self.Name..": Rams is negative")return true elseif self.NumAmmoCarts<0 then debug(false,b3.Identifier..": "..self.Name..": AmmoCarts is negative")return true end;return false end;RegisterBehavior(B_Reward_AI_SpawnAndAttackTerritory)function Reward_AI_SpawnAndAttackArea(...)return B_Reward_AI_SpawnAndAttackArea:new(...)end;B_Reward_AI_SpawnAndAttackArea={Name="Reward_AI_SpawnAndAttackArea",Description={en="Reward: Spawns AI troops and attacks everything within the specified area, except the players main buildings",de="Lohn: Erstellt KI Truppen und greift ein angegebenes Gebiet an, aber nicht die Hauptgebauede eines Spielers",fr="Récompense: Crée des troupes IA et attaque une zone spécifiée, mais pas les bâtiments principaux d'un joueur."},Parameter={{ParameterType.PlayerID,en="AI Player",de="KI Spieler",fr="Joueur AI"},{ParameterType.ScriptName,en="Spawn point",de="Erstellungsort",fr="Lieu de création"},{ParameterType.ScriptName,en="Target",de="Ziel",fr="Cible"},{ParameterType.Number,en="Radius",de="Radius",fr="Rayon"},{ParameterType.Number,en="Sword",de="Schwert",fr="Épéiste"},{ParameterType.Number,en="Bow",de="Bogen",fr="Archer"},{ParameterType.Custom,en="Soldier type",de="Soldatentyp",fr="Type de soldats"},{ParameterType.Custom,en="Reuse troops",de="Verwende best