ction"then return self.FuncName(unpack(self.i47ya_6aghw_frxil))end;return _G[self.FuncName](self,b3)end;function B_Trigger_MapScriptFunction:Debug(b3)if not self.FuncName then debug(false,b3.Identifier..": "..self.Name..": function reference is invalid!")return true end;if type(self.FuncName)~="function"and not _G[self.FuncName]then debug(false,b3.Identifier..": "..self.Name..": function does not exist!")return true end;return false end;RegisterBehavior(B_Trigger_MapScriptFunction)function Trigger_OnEffectDestroyed(...)return B_Trigger_OnEffectDestroyed:new(...)end;B_Trigger_OnEffectDestroyed={Name="Trigger_OnEffectDestroyed",Description={en="Trigger: Starts a quest after an effect was destroyed",de="Auslöser: Startet eine Quest, nachdem ein Effekt zerstoert wurde",fr="Déclencheur: Démarre une quête après la destruction d'un effet."},Parameter={{ParameterType.Default,en="Effect name",de="Effektname",fr="Nom de l'effet"}}}function B_Trigger_OnEffectDestroyed:GetTriggerTable()return{Triggers.Custom2,{self,self.CustomFunction}}end;function B_Trigger_OnEffectDestroyed:AddParameter(b4,b5)if b4==0 then self.EffectName=b5 end end;function B_Trigger_OnEffectDestroyed:CustomFunction()return not CONST_EFFECT_NAME_TO_ID[self.EffectName]or not Logic.IsEffectRegistered(CONST_EFFECT_NAME_TO_ID[self.EffectName])end;function B_Trigger_OnEffectDestroyed:Debug(b3)if not CONST_EFFECT_NAME_TO_ID[self.EffectName]then debug(false,b3.Identifier..": "..self.Name..": Effect has never existed")return true end end;RegisterBehavior(B_Trigger_OnEffectDestroyed)Lib.Core=Lib.Core or{}Lib.Core.Player={}CONST_PLAYER_NAMES={}Lib.Register("core/feature/Core_Player")function Lib.Core.Player:Initialize()for n=1,8 do CONST_PLAYER_NAMES[n]=""end;self:OverwriteNamingComforts()end;function Lib.Core.Player:OnSaveGameLoaded()end;function Lib.Core.Player:OnReportReceived(aG,...)end;function Lib.Core.Player:OverwriteNamingComforts()GetPlayerName=function(ag)return Lib.Core.Player:GetPlayerName(ag)end;SetPlayer