n local script.")error(IsExisting(h2.Name),"Entity does not exist.")local ii=Lib.NPC.Global:GetNpc(h2.Name)error(ii~=nil,"NPC was not found.")if ii.FollowDestination then return ii.Arrived==true end;return false end;API.NpcHasArrived=NpcHasArrived;Lib.NPC=Lib.NPC or{}Lib.NPC.Name="NPC"Lib.NPC.Global={Interactions={},NPC={},UseMarker=true}Lib.NPC.Local={}Lib.NPC.Text={StartConversation={de="Gespräch beginnen",en="Start conversation",fr="Conversation"}}CONST_LAST_NPC_INTERACTED=0;CONST_LAST_HERO_INTERACTED=0;Lib.Require("comfort/GetDistance")Lib.Require("comfort/GetClosestToTarget")Lib.Require("comfort/LookAt")Lib.Require("comfort/Move")Lib.Require("core/Core")Lib.Require("module/entity/NPC_API")Lib.Require("module/entity/NPC_Behavior")Lib.Register("module/entity/NPC")function Lib.NPC.Global:Initialize()if not self.IsInstalled then Report.NpcInteraction=CreateReport("Event_NpcInteraction")self:OverrideQuestFunctions()RequestHiResJob(function()if Logic.GetTime()>1 then Lib.NPC.Global:InteractionTriggerController()end end)RequestJob(function()Lib.NPC.Global:InteractableMarkerController()Lib.NPC.Global:NpcFollowHeroController()end)Lib.NPC.Local=nil end;self.IsInstalled=true end;function Lib.NPC.Global:OnSaveGameLoaded()end;function Lib.NPC.Global:OnReportReceived(aG,...)if aG==Report.LoadingFinished then self.LoadscreenClosed=true elseif aG==Report.NpcInteraction then CONST_LAST_NPC_INTERACTED=arg[1]CONST_LAST_HERO_INTERACTED=arg[2]self.Interactions[arg[1]]=self.Interactions[arg[1]]or{}if self.Interactions[arg[1]][arg[2]]then if Logic.GetCurrentTurn()<=self.Interactions[arg[1]][arg[2]]+5 then return end end;self.Interactions[arg[1]][arg[2]]=Logic.GetCurrentTurn()self:PerformNpcInteraction(arg[3])end end;function Lib.NPC.Global:CreateNpc(h2)self.NPC[h2.Name]={Name=h2.Name,Active=true,Arrived=false,Type=h2.Type or 1,Player=h2.Player or{1,2,3,4,5,6,7,8},WrongPlayerAction=h2.WrongPlayerAction,Hero=h2.Hero,WrongHeroAction=h2.WrongHeroAction,Distance=h2.Distance or 350,Conditi