tTime()if b7.WrongPlayerAction and io<ip then self.NPC[dr].LastWongPlayerTick=ip;b7:WrongPlayerAction(ag)end end end end;return im end;function Lib.NPC.Global:InteractionIsAppropriateHero(dr)local im=true;if self.NPC[dr]then local b7=self.NPC[dr]if b7.Hero~=nil then if type(b7.Hero)=="table"then im=table.contains(b7.Hero,Logic.GetEntityName(CONST_LAST_HERO_INTERACTED))end;im=b7.Hero==Logic.GetEntityName(CONST_LAST_HERO_INTERACTED)if not im then local io=(b7.WrongHeroTick or 0)+1;local ip=Logic.GetTime()if b7.WrongHeroAction and io<ip then self.NPC[dr].WrongHeroTick=ip;b7:WrongHeroAction(CONST_LAST_HERO_INTERACTED)end end end end;return im end;function Lib.NPC.Global:GetEntityMovementTarget(an)local eN=GetFloat(an,CONST_SCRIPTING_VALUES.Destination.X)local eO=GetFloat(an,CONST_SCRIPTING_VALUES.Destination.Y)return{X=eN,Y=eO}end;function Lib.NPC.Global:RotateActorsToEachother(ag)local iq={}Logic.GetKnights(ag,iq)for g,h in pairs(iq)do local aF=self:GetEntityMovementTarget(h)local C,D,E=Logic.EntityGetPos(CONST_LAST_NPC_INTERACTED)if math.floor(aF.X)==math.floor(C)and math.floor(aF.Y)==math.floor(D)then C,D,E=Logic.EntityGetPos(h)Logic.MoveEntity(h,C,D)LookAt(h,CONST_LAST_NPC_INTERACTED)end end;LookAt(CONST_LAST_HERO_INTERACTED,CONST_LAST_NPC_INTERACTED)LookAt(CONST_LAST_NPC_INTERACTED,CONST_LAST_HERO_INTERACTED)end;function Lib.NPC.Global:AdjustHeroTalkingDistance(N)local aa=N*GetFloat(CONST_LAST_NPC_INTERACTED,CONST_SCRIPTING_VALUES.Size)if GetDistance(CONST_LAST_HERO_INTERACTED,CONST_LAST_NPC_INTERACTED)<=aa*0.7 then local Q=Logic.GetEntityOrientation(CONST_LAST_NPC_INTERACTED)local aw,ax,ay=Logic.EntityGetPos(CONST_LAST_HERO_INTERACTED)local aA=aw+aa*0.5*math.cos(math.rad(Q))local aB=ax+aa*0.5*math.sin(math.rad(Q))local al=Logic.CreateEntityOnUnblockedLand(Entities.XD_ScriptEntity,aA,aB,0,0)local ir,is,it=Logic.EntityGetPos(al)Logic.MoveSettler(CONST_LAST_HERO_INTERACTED,ir,is)RequestHiResJob(function(il,iu,iv)if Logic.GetTime()>iv+0.5 and Logic.IsEntityMoving(il)=