.IOMine.Local=nil end;self.IsInstalled=true end;function Lib.IOMine.Global:OnSaveGameLoaded()end;function Lib.IOMine.Global:OnReportReceived(aG,...)if aG==Report.LoadingFinished then self.LoadscreenClosed=true elseif aG==Report.ObjectReset then if CONST_IO[arg[1]]and CONST_IO[arg[1]].IsInteractiveMine then self:ResetIOMine(arg[1],CONST_IO[arg[1]].Type)end elseif aG==Report.ObjectDelete then if CONST_IO[arg[1]].IsInteractiveMine and CONST_IO[arg[1]].Type then ReplaceEntity(arg[1],CONST_IO[arg[1]].Type)end end end;function Lib.IOMine.Global:CreateIOMine(ah,i,gi,du,gk,lu,dw,f_,lv,hr)local lw=self:ResetIOMine(ah,i)local kn={14,10}local lx;if i==Entities.R_IronMine then lx="Names/R_IronMine"kn={14,10}end;if i==Entities.R_StoneMine then lx="Names/R_StoneMine"kn={14,10}end;SetupObject{Name=ah,IsInteractiveMine=true,Title=gi or lx,Text=du,Texture=kn,Type=i,ResourceAmount=lu or 250,RefillAmount=dw or 75,Costs=gk,InvisibleBlocker=lw,Distance=1200,Waittime=0,ConditionInfo=lv,AdditionalCondition=f_,AdditionalAction=hr,Condition=function(h2)if h2.AdditionalCondition then return h2:AdditionalCondition(h2)end;return true end,Action=function(h2,iw,ag)local al=ReplaceEntity(h2.Name,h2.Type)SetResourceAmount(al,h2.ResourceAmount,h2.RefillAmount)DestroyEntity(h2.InvisibleBlocker)SendReport(Report.InteractiveMineErected,h2.Name,iw,ag)SendReportToLocal(Report.InteractiveMineErected,h2.Name,iw,ag)if h2.AdditionalAction then h2.AdditionalAction(h2,iw,ag)end end}end;function Lib.IOMine.Global:ResetIOMine(dr,i)if CONST_IO[dr]then DestroyEntity(CONST_IO[dr].InvisibleBlocker)end;local u=ReplaceEntity(dr,Entities.XD_ScriptEntity)local ly=Models.Doodads_D_SE_ResourceIron_Wrecked;if i==Entities.R_StoneMine then ly=Models.R_SE_ResorceStone_10 end;Logic.SetVisible(u,true)Logic.SetModel(u,ly)local C,D,E=Logic.EntityGetPos(u)local lw=Logic.CreateEntity(Entities.D_ME_Rock_Set01_B_07,C,D,0,0)Logic.SetVisible(lw,false)if CONST_IO[dr]then CONST_IO[dr].InvisibleBlocker=lw end;return lw end;function Lib.I