module/entity/EntityEvent")function Lib.EntityEvent.Global:Initialize()Report.SettlerAttracted=CreateReport("Event_SettlerAttracted")Report.EntitySpawned=CreateReport("Event_EntitySpawned")Report.EntityDestroyed=CreateReport("Event_EntityDestroyed")Report.EntityHurt=CreateReport("Event_EntityHurt")Report.EntityKilled=CreateReport("Event_EntityKilled")Report.EntityOwnerChanged=CreateReport("Event_EntityOwnerChanged")Report.EntityResourceChanged=CreateReport("Event_EntityResourceChanged")Report.ThiefInfiltratedBuilding=CreateReport("Event_ThiefInfiltratedBuilding")Report.ThiefDeliverEarnings=CreateReport("Event_ThiefDeliverEarnings")Report.BuildingConstructed=CreateReport("Event_BuildingConstructed")Report.BuildingUpgradeCollapsed=CreateReport("Event_BuildingUpgradeCollapsed")Report.BuildingUpgraded=CreateReport("Event_BuildingUpgraded")self:StartTriggers()self:OverrideCallback()self:OverrideLogic()end;function Lib.EntityEvent.Global:OnSaveGameLoaded()self:OverrideLogic()end;function Lib.EntityEvent.Global:OnReportReceived(aG,...)if aG==Report.LoadscreenClosed then self.LoadscreenClosed=true elseif aG==Report.EntityHurt then self.AttackedEntities[arg[3]]={arg[1],300}end end;function Lib.EntityEvent.Global:CleanTaggedAndDeadEntities()for g,h in pairs(self.AttackedEntities)do self.AttackedEntities[g][2]=h[2]-1;if h[2]<=0 then self.AttackedEntities[g]=nil else if IsExisting(g)and IsExisting(h[1])and Logic.IsKnight(g)then if Logic.KnightGetResurrectionProgress(g)~=1 then local g8=Logic.EntityGetPlayer(g)local g9=Logic.EntityGetPlayer(h[1])self:TriggerEntityKilledEvent(g,g8,h[1],g9)self.AttackedEntities[g]=nil end end end end end;function Lib.EntityEvent.Global:OverrideCallback()GameCallback_SettlerSpawned_Orig_QSB_EntityCore=GameCallback_SettlerSpawned;GameCallback_SettlerSpawned=function(ag,an)GameCallback_SettlerSpawned_Orig_QSB_EntityCore(ag,an)Lib.EntityEvent.Global:TriggerSettlerArrivedEvent(ag,an)end;GameCallback_OnBuildingConstructionComplete_Orig_QSB_EntityCore=GameCallback_OnBuildingConstructionComplete;GameCallback_OnBuildingConstructionComplete=function(ag,an)GameCallback_OnBuildingConstructionComplete_Orig_QSB_EntityCore(ag,an)Lib.EntityEvent.Global:TriggerConstructionCompleteEvent(ag,an)end;GameCallback_FarmAnimalChangedPlayerID_Orig_QSB_EntityCore=GameCallback_FarmAnimalChangedPlayerID;GameCallback_FarmAnimalChangedPlayerID=function(ag,lz,lA)GameCallback_FarmAnimalChangedPlayerID_Orig_QSB_EntityCore(ag,lz,lA)local lB=Logic.EntityGetPlayer(lA)local lC=Logic.EntityGetPlayer(lz)Lib.EntityEvent.Global:TriggerEntityOnwershipChangedEvent(lA,lB,lz,lC)end;GameCallback_EntityCaptured_Orig_QSB_EntityCore=GameCallback_EntityCaptured;GameCallback_EntityCaptured=function(lA,lD,lz,lE)GameCallback_EntityCaptured_Orig_QSB_EntityCore(lA,lD,lz,lE)Lib.EntityEvent.Global:TriggerEntityOnwershipChangedEvent(lA,lD,lz,lE)end;GameCallback_CartFreed_Orig_QSB_EntityCore=GameCallback_CartFreed;GameCallback_CartFreed=function(lA,lD,lz,lE)GameCallback_CartFreed_Orig_QSB_EntityCore(lA,lD,lz,lE)Lib.EntityEvent.Global:TriggerEntityOnwershipChangedEvent(lA,lD,lz,lE)end;GameCallback_OnThiefDeliverEarnings_Orig_QSB_EntityCore=GameCallback_OnThiefDeliverEarnings;GameCallback_OnThiefDeliverEarnings=function(lF,lG,hZ,lH)GameCallback_OnThiefDeliverEarnings_Orig_QSB_EntityCore(lF,lG,hZ,lH)local lI=Logic.EntityGetPlayer(hZ)Lib.EntityEvent.Global:TriggerThiefDeliverEarningsEvent(lG,lF,hZ,lI,lH)end;GameCallback_OnThiefStealBuilding_Orig_QSB_EntityCore=GameCallback_OnThiefStealBuilding;GameCallback_OnThiefStealBuilding=function(lG,lF,hZ,lJ)Lib.EntityEvent.Global:TriggerThiefStealFromBuildingEvent(lG,lF,hZ,lJ)end;GameCallback_OnBuildingUpgraded_Orig_QSB_EntityCore=GameCallback_OnBuildingUpgradeFinished;GameCallback_OnBuildingUpgradeFinished=function(ag,an,lK)GameCallback_OnBuildingUpgraded_Orig_QSB_EntityCore(ag,an,lK)Lib.EntityEvent.Global:TriggerUpgradeCompleteEvent(ag,an,lK)end;GameCallback_OnUpgradeLevelCollapsed_Orig_QSB_EntityCore=GameCallback_OnUpgradeLevelCollapsed;GameCallback_OnUpgradeLevelCollapsed=function(ag,hZ,lK)GameCallback_OnUpgradeLevelCollapsed_Orig_QSB_EntityCore(ag,hZ,lK)Lib.EntityEvent.Global:TriggerUpgradeCollapsedEvent(ag,hZ,lK)end end;function Lib.EntityEvent.Global:OverrideLogic()self.Logic_ChangeEntityPlayerID=Logic.ChangeEntityPlayerID;Logic.ChangeEntityPlayerID=function(...)local fC={arg[1]}local lB=Logic.EntityGetPlayer(arg[1])local bY={self.Logic_ChangeEntityPlayerID(unpack(arg))}local lC=Logic.EntityGetPlayer(bY[1])Lib.EntityEvent.Global:TriggerEntityOnwershipChangedEvent(fC,lB,bY,lC)return bY end;self.Logic_ChangeSettlerPlayerID=Logic.ChangeSettlerPlayerID;Logic.ChangeSettlerPlayerID=function(...)local fC={arg[1]}local lB=Logic.EntityGetPlayer(arg[1])local lL={Logic.GetSoldiersAttachedToLeader(arg[1])}if lL[1]and lL[1]>0 then for f=2,lL[1]+1 do table.insert(fC,lL[f])end end;local bY={self.Logic_ChangeSettlerPlayerID(unpack(arg))}local lM={Logic.GetSoldiersAttachedToLeader(bY[1])}if lM[1]and lM[1]>0 then for f=2,lM[1]+1 do table.insert(bY,lM[f])end end;local lC=Logic.EntityGetPlayer(bY[1])Lib.EntityEvent.Global:TriggerEntityOnwershipChangedEvent(fC,lB,bY,lC)return bY[1]end end;function Lib.EntityEvent.Global:StartTriggers()self.JobID.EveryTurn=RequestJobByEventType(Events.LOGIC_EVENT_EVERY_TURN,function()if Logic.GetCurrentTurn()>0 then Lib.EntityEvent.Global:CleanTaggedAndDeadEntities()Lib.EntityEvent.Global:CheckOnSpawnerEntities()end end)self.JobID.EverySecond=RequestJobByEventType(Events.LOGIC_EVENT_EVERY_SECOND,function()local lN={Entities.R_IronMine,Entities.R_StoneMine}for f=1,#lN do local lO=Logic.GetEntitiesOfType(lN[f])for aX=1,#lO do local dq=self.MineAmounts[lO[aX]]local lP=Logic.GetResourceDoodadGoodAmount(lO[aX])if dq and lP and dq~=lP then local l=Logic.GetResourceDoodadGoodType(lO[aX])SendReport(Report.EntityResourceChanged,lO[aX],l,dq,lP)SendReportToLocal(Report.EntityResourceChanged,lO[aX],l,dq,lP)end;self.MineAmounts[lO[aX]]=lP end end end)self.JobID.EntityDestroyed=RequestJobByEventType(Events.LOGIC_EVENT_ENTITY_DESTROYED,function()local lQ=Event.GetEntityID()local g8=Logic.EntityGetPlayer(lQ)Lib.EntityEvent.Global:TriggerEntityDestroyedEvent(lQ,g8)if Lib.EntityEvent.Global.AttackedEntities[lQ]~=nil then local lR=Lib.EntityEvent.Global.AttackedEntities[lQ][1]local g9=Logic.EntityGetPlayer(lR)Lib.EntityEvent.Global.AttackedEntities[lQ]=nil;Lib.EntityEvent.Global:TriggerEntityKilledEvent(lQ,g8,lR,g9)end end)self.JobID.EveryHurn=RequestJobByEventType(Events.LOGIC_EVENT_ENTITY_HURT_ENTITY,function()local lQ=Event.GetEntityID1()local g8=Logic.EntityGetPlayer(lQ)local lR=Event.GetEntityID2()local g9=Logic.EntityGetPlayer(lR)SendReport(Report.EntityHurt,lQ,g8,lR,g9)SendReportToLocal(Report.EntityHurt,lQ,g8,lR,g9)end)end;function Lib.EntityEvent.Global:CheckOnSpawnerEntities()local lS={}for f=1,#self.DynamicSpawnerTypes do if Entities[self.DynamicSpawnerTypes[f]]then if Logic.GetCurrentTurn()%10==f then for g,h in pairs(Logic.GetEntitiesOfType(Entities[self.DynamicSpawnerTypes[f]]))do table.insert(lS,h)end end end end;for f=1,#self.StaticSpawnerTypes do if Entities[self.StaticSpawnerTypes[f]]then if Logic.GetCurrentTurn()%10==f then for g,h in pairs(Logic.GetEntitiesOfType(Entities[self.StaticSpawnerTypes[f]]))do table.insert(lS,h)end end end end;for f=1,#lS do for g,h in pairs{Logic.GetSpawnedEntities(lS[f])}do if not self.RegisteredEntities[h]then self:TriggerEntitySpawnedEvent(h,lS[f])self.RegisteredEntities[h]=lS[f]end end end end;function Lib.EntityEvent.Global:TriggerEntityOnwershipChangedEvent(lT,lU,lV,lW)lT=type(lT)~="table"and{lT}or lT;lV=type(lV)~="table"and{lV}or lV;assert(#lT==#lV,"Sums of entities with changed owner does not add up!")for f=1,#lT do SendReport(Report.EntityOwnerChanged,lT[f],lU,lV[f],lW)SendReportToLocal(Report.EntityOwnerChanged,lT[f],lU,lV[f],lW)end end;function Lib.EntityEvent.Global:TriggerThiefDeliverEarningsEvent(lG,lF,hZ,lJ,lH)SendReport(Report.ThiefDeliverEarnings,lG,lF,hZ,lJ,lH)SendReportToLocal(Report.ThiefDeliverEarnings,lG,lF,hZ,lJ,lH)end;function Lib.EntityEvent.Global:TriggerThiefStealFromBuildingEvent(lG,lF,hZ,lJ)local lX=Logic.GetHeadquarters(lJ)local hD=Logic.GetCathedral(lJ)local eS=Logic.GetStoreHouse(lJ)local lY=Logic.IsEntityInCategory(eS,EntityCategories.VillageStorehouse)==1;local lZ=Logic.GetEntityType(hZ)if eS==hZ and(not lY or lX==0)then if not self.DisableThiefStorehouseHeist then GameCallback_OnThiefStealBuilding_Orig_QSB_EntityCore(lG,lF,hZ,lJ)end end;if hD==hZ then if not self.DisableThiefCathedralSabotage then GameCallback_OnThiefStealBuilding_Orig_QSB_EntityCore(lG,lF,hZ,lJ)end end;if Framework.GetGameExtraNo()>0 and lZ==Entities.B_Cistern then if not self.DisableThiefCisternSabotage then GameCallback_OnThiefStealBuilding_Orig_QSB_EntityCore(lG,lF,hZ,lJ)end end;SendReport(Report.ThiefInfiltratedBuilding,lG,lF,hZ,lJ)SendReportToLocal(Report.ThiefInfiltratedBuilding,lG,lF,hZ,lJ)end;function Lib.EntityEvent.Global:TriggerEntitySpawnedEvent(an,l_)local n=Logic.EntityGetPlayer(an)SendReport(Report.EntitySpawned,an,n,l_)SendReportToLocal(Report.EntitySpawned,an,n,l_)end;function Lib.EntityEvent.Global:TriggerSettlerArrivedEvent(ag,an)SendReport(Report.SettlerAttracted,an,ag)SendReportToLocal(Report.SettlerAttracted,an,ag)end;function Lib.EntityEvent.Global:TriggerEntityDestroyedEvent(an,ag)SendReport(Report.EntityDestroyed,an,ag)SendReportToLocal(Report.EntityDestroyed,an,ag)end;function Lib.EntityEvent.Global:TriggerEntityKilledEvent(m0,m1,m2,m3)SendReport(Report.EntityKilled,m0,m1,m2,m3)SendReportToLocal(Report.EntityKilled,m0,m1,m2,m3)end;function Lib.EntityEvent.Global:TriggerConstructionCompleteEvent(ag,an)SendReport(Report.BuildingConstructed,an,ag)SendReportToLocal(Report.BuildingConstructed,an,ag)end;function Lib.EntityEvent.Global:TriggerUpgradeCompleteEvent(ag,an,lK)SendReport(Report.BuildingUpgraded,an,ag,lK)SendReportToLocal(Report.BuildingUpgraded,an,ag,lK)end;function Lib.EntityEvent.Global:TriggerUpgradeCollapsedEvent(ag,an,lK)SendReport(Report.BuildingUpgradeCollapsed,an,ag,lK)SendReportToLocal(Report.BuildingUpgradeCollapsed,an,ag,lK)end;function Lib.EntityEvent.Local:Initialize()Report.SettlerAttracted=CreateReport("Event_SettlerAttracted")Report.EntitySpawned=CreateReport("Event_EntitySpawned")Report.EntityDestroyed=CreateReport("Event_EntityDestroyed")Report.EntityHurt=CreateReport("Event_EntityHurt")Report.EntityKilled=CreateReport("Event_EntityKilled")Report.EntityOwnerChanged=CreateReport("Event_EntityOwnerChanged")Report.EntityResourceChanged=CreateReport("Event_EntityResourceChanged")Report.ThiefInfiltratedBuilding=CreateReport("Event_ThiefInfiltratedBuilding")Report.ThiefDeliverEarnings=CreateReport("Event_ThiefDeliverEarnings")Report.BuildingConstructed=CreateReport("Event_BuildingConstructed")Report.BuildingUpgradeCollapsed=CreateReport("Event_BuildingUpgradeCollapsed")Report.BuildingUpgraded=CreateReport("Event_BuildingUpgraded")end;function Lib.EntityEvent.Local:OnReportReceived(aG,...)if aG==Report.LoadscreenClosed then self.LoadscreenClosed=true end end;RegisterModule(Lib.EntityEvent.Name)Lib.Register("module/entity/EntitySelection_Text")Lib.EntitySelection=Lib.EntitySelection or{}Lib.EntitySelection.Text={Tooltips={KnightButton={Title={de="Ritter selektieren",en="Select Knight",fr="Sélectionner le chevalier"},Text={de="- Klick selektiert den Ritter {cr}- Doppelklick springt zum Ritter{cr}- UMSCH halten selektiert alle Ritter",en="- Click selects the knight {cr}- Double click jumps to knight{cr}- Press SHIFT to select all knights",fr="- Clic sélectionne le chevalier {cr}- Double-clic saute au chevalier{cr}- Maintenir SHIFT sélectionne tous les chevaliers"}},BattalionButton={Title={de="Militär selektieren",en="Select Units",fr="Sélectionner les unitées"},Text={de="- Selektiert alle Einheiten {cr}- UMSCH halten selektiert Militär {cr}- ALT halten selektiert Kriegsmaschinen {cr}- STRG halten selektiert Diebe",en="- Selects all units {cr}- Holding SHIFT selects military {cr}- Holdin