ion:Debug(b3)if type(self.Reputation)~="number"or self.Reputation<0 or self.Reputation>100 then error(b3.Identifier..": "..self.Name..": Reputation must be between 0 and 100!")return true end;return false end;RegisterBehavior(B_Goal_CityReputation)function Goal_DestroySpawnedEntities(...)return B_Goal_DestroySpawnedEntities:new(...)end;B_Goal_DestroySpawnedEntities={Name="Goal_DestroySpawnedEntities",Description={en="Goal: Destroy all entities spawned at the spawnpoint.",de="Ziel: Zerstöre alle Entitäten, die bei dem Spawnpoint erzeugt wurde.",fr="Objectif: Détruire toutes les entités créées au point d'apparition."},Parameter={{ParameterType.ScriptName,en="Spawnpoint",de="Spawnpoint",fr="Point d'émergence"},{ParameterType.Number,en="Amount",de="Menge",fr="Quantité"},{ParameterType.Custom,en="Name is prefixed",de="Name ist Präfix",fr="Le nom est un préfixe"}}}function B_Goal_DestroySpawnedEntities:GetGoalTable()if self.Prefixed then local d4=table.remove(self.SpawnPoint)local f=1;while IsExisting(d4 ..f)do table.insert(self.SpawnPoint,d4 ..f)f=f+1 end;assert(#self.SpawnPoint>0,"No spawnpoints found!")end;return{Objective.DestroyEntities,3,self.SpawnPoint,self.Amount}end;function B_Goal_DestroySpawnedEntities:AddParameter(b4,b5)if b4==0 then self.SpawnPoint={b5}elseif b4==1 then self.Amount=b5*1 elseif b4==2 then b5=b5 or"false"self.Prefixed=ToBoolean(b5)end end;function B_Goal_DestroySpawnedEntities:GetMsgKey()local al=GetID(self.SpawnPoint[1])if al~=0 then local fF=Logic.GetEntityTypeName(Logic.GetEntityType(al))if Logic.IsEntityTypeInCategory(al,EntityCategories.AttackableBuilding)==1 then return"Quest_Destroy_Leader"elseif fF:find("Bear")or fF:find("Lion")or fF:find("Tiger")or fF:find("Wolf")then return"Quest_DestroyEntities_Predators"elseif fF:find("Military")or fF:find("Cart")then return"Quest_DestroyEntities_Unit"end end;return"Quest_DestroyEntities"end;function B_Goal_DestroySpawnedEntities:GetCustomData(b4)if b4==2 then return{"false","true"}end end;RegisterBehavior(B_Goal_DestroySpawnedEntities)function Goal_StealGold(...)return B_Goal_StealGold:new(...)end;B_Goal_StealGold={Name="Goal_StealGold",Description={en="Goal: Steal an explicit amount of gold from a players or any players city buildings.",de="Ziel: Diebe sollen eine bestimmte Menge Gold aus feindlichen Stadtgebäuden stehlen.",fr="Objectif: les voleurs doivent dérober une certaine quantité d'or dans les bâtiments urbains ennemis."},Parameter={{ParameterType.Number,en="Amount on Gold",de="Zu stehlende Menge",fr="Quantité à voler"},{ParameterType.Custom,en="Target player",de="Spieler von dem gestohlen wird",fr="Joueur à qui l'on vole"},{ParameterType.Custom,en="Cheat earnings",de="Einnahmen generieren",fr="Générer des revenus"},{ParameterType.Custom,en="Print progress",de="Fortschritt ausgeben",fr="Afficher les progrès"}}}function B_Goal_StealGold:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_StealGold:AddParameter(b4,b5)if b4==0 then self.Amount=b5*1 elseif b4==1 then local n=tonumber(b5)or-1;self.Target=n*1 elseif b4==2 then b5=b5 or"false"self.CheatEarnings=ToBoolean(b5)elseif b4==3 then b5=b5 or"true"self.Printout=ToBoolean(b5)end;self.StohlenGold=0 end;function B_Goal_StealGold:GetCustomData(b4)if b4==1 then return{"-",1,2,3,4,5,6,7,8}elseif b4==2 then return{"true","false"}end end;function B_Goal_StealGold:SetDescriptionOverwrite(b3)local nF=Localize({de=" anderen Spielern ",en=" different parties ",fr=" d'autres joueurs "})if self.Target~=-1 then nF=GetPlayerName(self.Target)if nF==nil or nF==""then nF=" PLAYER_NAME_MISSING "end end;if self.CheatEarnings then local nG={self.Target}if self.Target==-1 then nG={1,2,3,4,5,6,7,8}end;for f=1,#nG,1 do if f~=b3.ReceivingPlayer and Logic.GetStoreHouse(f)~=0 then local jP={Logic.GetPlayerEntitiesInCategory(f,EntityCategories.CityBuilding)}for aX=1,#jP,1 do local nH=Logic.GetBuildingProductEarnings(jP[aX])if nH<45 and Logic.GetTime()%5==0 then Logic.SetBuildingEarnings(jP[aX],nH+1)end end end end end;local bu=self.Amount-self.StohlenGold;bu=bu>0 and bu or 0;local gK={de="Gold von %s stehlen {cr}{cr}Aus Stadtgebäuden zu stehlende Goldmenge: %d",en="Steal gold from %s {cr}{cr}Amount on gold to steal from city buildings: %d",fr="Voler l'or de %s {cr}{cr}Quantité d'or à voler dans les bâtiments de la ville : %d"}return"{center}"..string.format(Localize(gK),nF,bu)end;function B_Goal_StealGold:CustomFunction(b3)if Lib.Core.Quest then Lib.Core.Quest:ChangeCustomQuestCaptionText(self:SetDescriptionOverwrite(b3),b3)end;if self.StohlenGold>=self.Amount then return true end;return nil end;function B_Goal_StealGold:GetIcon()return{5,13}end;function B_Goal_StealGold:Debug(b3)if tonumber(self.Amount)==nil and self.Amount<0 then error(b3.Identifier..": "..self.Name..": amount can not be negative!")return true end;return false end;function B_Goal_StealGold:Reset(b3)self.StohlenGold=0 end;RegisterBehavior(B_Goal_StealGold)function Goal_StealFromBuilding(...)return B_Goal_StealFromBuilding:new(...)end;B_Goal_StealFromBuilding={Name="Goal_StealFromBuilding",Description={en="Goal: The player has to steal from a building. Not a castle and not a village storehouse!",de="Ziel: Der Spieler muss ein bestimmtes Gebäude bestehlen. Dies darf keine Burg und kein Dorflagerhaus sein!",fr="Objectif: Le joueur doit voler un bâtiment spécifique. Il ne peut s'agir ni d'un château ni d'un entrepôt de village !"},Parameter={{ParameterType.ScriptName,en="Building",de="Gebäude",fr="Bâtiment"},{ParameterType.Custom,en="Cheat earnings",de="Einnahmen generieren",fr="Générer des revenus"}}}function B_Goal_StealFromBuilding:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_StealFromBuilding:AddParameter(b4,b5)if b4==0 then self.Building=b5 elseif b4==1 then b5=b5 or"false"self.CheatEarnings=ToBoolean(b5)end;self.RobberList={}end;function B_Goal_StealFromBuilding:GetCustomData(b4)if b4==1 then return{"true","false"}end end;function B_Goal_StealFromBuilding:SetDescriptionOverwrite(b3)local nI=Logic.IsEntityInCategory(GetID(self.Building),EntityCategories.Cathedrals)==1;local nJ=Logic.GetEntityType(GetID(self.Building))==Entities.B_StoreHouse;local nK=Logic.GetEntityType(GetID(self.Building))==Entities.B_Cistern;local gK;if nI then gK={de="Sabotage {cr}{cr} Sendet einen Dieb und sabotiert die markierte Kirche.",en="Sabotage {cr}{cr} Send a thief to sabotage the marked chapel.",fr="Sabotage {cr}{cr} Envoyez un voleur pour saboter la chapelle marquée."}elseif nJ then gK={de="Lagerhaus bestehlen {cr}{cr} Sendet einen Dieb in das markierte Lagerhaus.",en="Steal from storehouse {cr}{cr} Steal from the marked storehouse.",fr="Voler un entrepôt {cr}{cr} Envoie un voleur dans l'entrepôt marqué."}elseif nK then gK={de="Sabotage {cr}{cr} Sendet einen Dieb und sabotiert den markierten Brunnen.",en="Sabotage {cr}{cr} Send a thief and break the marked well of the enemy.",fr="Sabotage {cr}{cr} Envoie un voleur et sabote le puits marqué."}else gK={de="Gebäude bestehlen {cr}{cr} Sendet einen Dieb und bestehlt das markierte Gebäude.",en="Steal from building {cr}{cr} Send a thief to steal from the marked building.",fr="Voler un bâtiment {cr}{cr} Envoie un voleur et vole le bâtiment marqué."}end;return"{center}"..Localize(gK)end;function B_Goal_StealFromBuilding:CustomFunction(b3)if not IsExisting(self.Building)then if self.Marker then Logic.DestroyEffect(self.Marker)end;return false end;if not self.Marker then local aI=GetPosition(self.Building)self.Marker=Logic.CreateEffect(EGL_Effects.E_Questmarker,aI.X,aI.Y,0)end;if self.CheatEarnings then local jT=GetID(self.Building)local nH=Logic.GetBuildingProductEarnings(jT)if Logic.IsEntityInCategory(jT,EntityCategories.CityBuilding)==1 and nH<45 and Logic.GetTime()%5==0 then Logic.SetBuildingEarnings(jT,nH+1)end end;if self.SuccessfullyStohlen then Logic.DestroyEffect(self.Marker)return true end;return nil end;function B_Goal_StealFromBuilding:GetIcon()return{5,13}end;function B_Goal_StealFromBuilding:Debug(b3)local nL=Logic.GetEntityTypeName(Logic.GetEntityType(GetID(self.Building)))local nM=Logic.IsEntityInCategory(GetID(self.Building),EntityCategories.Headquarters)==1;if Logic.IsBuilding(GetID(self.Building))==0 then error(b3.Identifier..": "..self.Name..": target is not a building")return true elseif not IsExisting(self.Building)then error(b3.Identifier..": "..self.Name..": target is destroyed :(")return true elseif string.find(nL,"B_NPC_BanditsHQ")or string.find(nL,"B_NPC_Cloister")or string.find(nL,"B_NPC_StoreHouse")then error(b3.Identifier..": "..self.Name..": village storehouses are not allowed!")return true elseif nM then error(b3.Identifier..": "..self.Name..": use Goal_StealInformation for headquarters!")return true end;return false end;function B_Goal_StealFromBuilding:Reset(b3)self.SuccessfullyStohlen=false;self.RobberList={}self.Marker=nil end;function B_Goal_StealFromBuilding:Interrupt(b3)Logic.DestroyEffect(self.Marker)end;RegisterBehavior(B_Goal_StealFromBuilding)function Goal_SpyOnBuilding(...)return B_Goal_SpyOnBuilding:new(...)end;B_Goal_SpyOnBuilding={Name="Goal_SpyOnBuilding",IconOverwrite={5,13},Description={en="Goal: Infiltrate a building with a thief. A thief must be able to steal from the target building.",de="Ziel: Infiltriere ein Gebäude mit einem Dieb. Nur mit Gebaueden möglich, die bestohlen werden koennen.",fr="Objectif: Infiltrer un bâtiment avec un voleur. Seulement possible avec des bâtiments qui peuvent être volés."},Parameter={{ParameterType.ScriptName,en="Target Building",de="Zielgebäude",fr="Bâtiment cible"},{ParameterType.Custom,en="Cheat earnings",de="Einnahmen generieren",fr="Générer des revenus"},{ParameterType.Custom,en="Destroy Thief",de="Dieb löschen",fr="Supprimer le voleur"}}}function B_Goal_SpyOnBuilding:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_SpyOnBuilding:AddParameter(b4,b5)if b4==0 then self.Building=b5 elseif b4==1 then b5=b5 or"false"self.CheatEarnings=ToBoolean(b5)elseif b4==2 then b5=b5 or"true"self.Delete=ToBoolean(b5)end end;function B_Goal_SpyOnBuilding:GetCustomData(b4)if b4==1 then return{"true","false"}end end;function B_Goal_SpyOnBuilding:SetDescriptionOverwrite(b3)if not b3.QuestDescription then local gK={de="Gebäude infriltrieren {cr}{cr}Spioniere das markierte Gebäude mit einem Dieb aus!",en="Infiltrate building {cr}{cr}Spy on the highlighted buildings with a thief!",fr="Infiltrer un bâtiment {cr}{cr}Espionner le bâtiment marqué avec un voleur!"}return Localize(gK)else return b3.QuestDescription end end;function B_Goal_SpyOnBuilding:CustomFunction(b3)if not IsExisting(self.Building)then if self.Marker then Logic.DestroyEffect(self.Marker)end;return false end;if not self.Marker then local aI=GetPosition(self.Building)self.Marker=Logic.CreateEffect(EGL_Effects.E_Questmarker,aI.X,aI.Y,0)end;if self.CheatEarnings then local jT=GetID(self.Building)if Logic.IsEntityInCategory(jT,EntityCategories.CityBuilding)==1 and Logic.GetBuildingEarnings(jT)<5 then Logic.SetBuildingEarnings(jT,5)end end;if self.Infiltrated then Logic.DestroyEffect(self.Marker)return true end;return nil end;function B_Goal_SpyOnBuilding:GetIcon()return self.IconOverwrite end;function B_Goal_SpyOnBuilding:Debug(b3)if Logic.IsBuilding(GetID(self.Building))==0 then error(b3.Identifier..": "..self.Name..": target is not a building")return true elseif not IsExisting(self.Building)then error(b3.Identifier..": "..self.Name..": target is destroyed :(")return true end;return false end;function B_Goal_SpyOnBuilding:Reset(b3)self.Infiltrated=false;self.Marker=nil end;function B_Goal_SpyOnBuilding:Interrupt(b3)Logic.DestroyEffect(self.Marker)end;RegisterBehavior(B_Goal_SpyOnBuilding)function Goal_DestroySoldiers(...)return B_Goal_DestroySoldiers:new(...)end;B_Goal_DestroySoldiers={Name="Goal_DestroySoldiers",Description={en="Goal: Destroy a given amount of enemy soldiers",de="Ziel: Zerstöre eine Anzahl gegnerischer Soldaten",fr="Objectif: Détruire un certain nombre de soldats ennemis"},Parameter={{ParameterType.PlayerID,en="Attacking Player",de="Angreifer",fr="Attaquant"},{ParameterType.PlayerID,en="Defending Player",de="Verteidiger",fr="Défenseur"},{ParameterType.Number,en="Amount",de="Anzahl",fr="Quantité"}},Text={de="{center}SOLDATEN ZERSTÖREN {cr}{cr}von der Partei: %s{cr}{cr}Anzahl: %d",en="{center}DESTROY SOLDIERS {cr}{cr}from faction: %s{cr}{cr}Amount: %d",fr="{center}DESTRUIRE DES SOLDATS {cr}{cr}de la faction: %s{cr}{cr}Nombre : %d"}}function B_Goal_DestroySoldiers:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_DestroySoldiers:AddParameter(b4,b5)if b4==0 then self.AttackingPlayer=b5*1 elseif b4==1 then self.AttackedPlayer=b5*1 elseif b4==2 then self.KillsNeeded=b5*1 end end;function B_Goal_DestroySoldiers:CustomFunction(b3)if not b3.QuestDescription or b3.QuestDescription==""then local bc=GetPlayerName(self.AttackedPlayer)or"Player "..self.AttackedPlayer;Lib.Core.Quest:ChangeCustomQuestCaptionText(string.format(Lib.Core.Text:Localize(self.Text),bc,self.KillsNeeded),b3)end;local nN=GetEnemySoldierKillsOfPlayer(self.AttackingPlayer,self.AttackedPlayer)if not self.KillstStart then self.KillstStart=nN end;if self.KillsNeeded<=nN-self.KillstStart then return true end end;function B_Goal_DestroySoldiers:Debug(b3)if Logic.GetStoreHouse(self.AttackingPlayer)==0 then error(b3.Identifier..": "..self.Name..": Player "..self.AttackinPlayer.." is dead :-(")return true elseif Logic.GetStoreHouse(self.AttackedPlayer)==0 then error(b3.Identifier..": "..self.Name..": Player "..self.AttackedPlayer.." is dead :-(")return true elseif self.KillsNeeded<0 then error(b3.Identifier..": "..self.Name..": Amount negative")return true end end;function B_Goal_DestroySoldiers:Reset()self.KillstStart=nil end;function B_Goal_DestroySoldiers:GetIcon()return{7,12}end;RegisterBehavior(B_Goal_DestroySoldiers)function Reprisal_SetPosition(...)return B_Reprisal_SetPosition:new(...)end;B_Reprisal_SetPosition={Name="Reprisal_SetPosition",Description={en="Reprisal: Places an entity relative to the position of another. The entity can look the target.",de="Vergeltung: Setzt eine Entity relativ zur Position einer anderen. Die Entity kann zum Ziel ausgerichtet werden.",fr="Rétribution: place une Entity vis-à-vis de l'emplacement d'une autre. L'entité peut être orientée vers la cible."},Parameter={{ParameterType.ScriptName,en="Entity",de="Entity",fr="Entité"},{ParameterType.ScriptName,en="Target position",de="Zielposition",fr="Position cible"},{ParameterType.Custom,en="Face to face",de="Ziel ansehen",fr="Voir la cible"},{ParameterType.Number,en="Distance",de="Zielentfernung",fr="Distance de la cible"}}}function B_Reprisal_SetPosition:GetReprisalTable()return{Reprisal.Custom,{self,self.CustomFunction}}end;function B_Reprisal_SetPosition:AddParameter(b4,b5)if b4==0 then self.Entity=b5 elseif b4==1 then self.Target=b5 elseif b4==2 then self.FaceToFace=ToBoolean(b5)elseif b4==3 then self.Distance=b5~=nil and tonumber(b5)or 100 end end;function B_Reprisal_SetPosition:CustomFunction(b3)if not IsExisting(self.Entity)or not IsExisting(self.Target)then return end;local c0=GetID(self.Entity)local nO=GetID(self.Target)local C,D,E=Logic.EntityGetPos(nO)if Logic.IsBuilding(nO)==1 then C,D=Logic.GetBuildingApproachPosition(nO)end;local nP=Logic.GetEntityOrientation(nO)+90;if self.FaceToFace then C=C+self.Distance*math.cos(math.rad(nP))D=D+self.Distance*math.sin(math.rad(nP))Logic.DEBUG_SetSettlerPosition(c0,C,D)LookAt(self.Entity,self.Target)else if Logic.IsBuilding(nO)==1 then C,D=Logic.GetBuildingApproachPosition(nO)end;Logic.DEBUG_SetSettlerPosition(c0,C,D)end end;function B_Reprisal_SetPosition:GetCustomData(b4)if b4==2 then return{"true","false"}end end;function B_Reprisal_SetPosition:Debug(b3)if self.FaceToFace then if tonumber(self.Distance)==nil or self.Distance<50 then error(b3.Identifier..": "..self.Name..": Distance is nil or to short!")return true end end;if not IsExisting(self.Entity)or not IsExisting(self.Target)then error(b3.Identifier..": "..self.Name..": Mover entity or target entity does not exist!")return true end;return false end;RegisterBehavior(B_Reprisal_SetPosition)function Reprisal_ChangePlayer(...)return B_Reprisal_ChangePlayer:new(...)end;B_Reprisal_ChangePlayer={Name="Reprisal_ChangePlayer",Description={en="Reprisal: Changes the owner of the entity or a battalion.",de="Vergeltung: Aendert den Besitzer einer Entity oder eines Battalions.",fr="Rétribution : Change le propriétaire d'une entité ou d'un bataillon."},Parameter={{ParameterType.ScriptName,en="Entity",de="Entity",fr="Entité"},{ParameterType.Custom,en="Player",de="Spieler",fr="Joueur"}}}function B_Reprisal_ChangePlayer:GetReprisalTable()return{Reprisal.Custom,{self,self.CustomFunction}}end;function B_Reprisal_ChangePlayer:AddParameter(b4,b5)if b4==0 then self.Entity=b5 elseif b4==1 then self.Player=tostring(b5)end end;function B_Reprisal_ChangePlayer:CustomFunction(b3)if not IsExisting(self.Entity)then return end;local bL=GetID(self.Entity)if Logic.IsLeader(bL)==1 then Logic.ChangeSettlerPlayerID(bL,self.Player)else Logic.ChangeEntityPlayerID(bL,self.Player)end end;function B_Reprisal_ChangePlayer:GetCustomData(b4)if b4==1 then return{"0","1","2","3","4","5","6","7","8"}end end;function B_Reprisal_ChangePlayer:Debug(b3)if not IsExisting(self.Entity)then error(b3.Identifier..": "..self.Name..": entity '"..self.Entity.."' does not exist!")return true end;return false end;RegisterBehavior(B_Reprisal_ChangePlayer)function Reprisal_SetVisible(...)return B_Reprisal_SetVisible:new(...)end;B_Reprisal_SetVisible={Name="Reprisal_SetVisible",Description={en="Reprisal: Changes the visibility of an entity. If the entity is a spawner the spawned entities will be affected.",de="Vergeltung: Setzt die Sichtbarkeit einer Entity. Handelt es sich um einen Spawner werden auch die gespawnten Entities beeinflusst.",fr="Rétribution: fixe la visibilité d'une Entité. S'il s'agit d'un spawn, les Entities spawnées sont également affectées."},Parameter={{ParameterType.ScriptName,en="Entity",de="Entity",fr="Entité"},{ParameterType.Custom,en="Visible",de="Sichtbar",fr="Visible"}}}function B_Reprisal_SetVisible:GetReprisalTable()return{Reprisal.Custom,{self,self.CustomFunction}}end;function B_Reprisal_SetVisible:AddParameter(b4,b5)if b4==0 then self.Entity=b5 elseif b4==1 then self.Visible=ToBoolean(b5)end end;function B_Reprisal_SetVisible:CustomFunction(b3)if not IsExisting(self.Entity)then return end;local bL=GetID(self.Entity)local bO=Logic.EntityGetPlayer(bL)local m9=Logic.GetEntityType(bL)local nQ=Logic.GetEntityTypeName(m9)if string.find(nQ,"^S_")or string.find(nQ,"^B_NPC_Bandits")or string.find(nQ,"^B_NPC_Barracks")then local nR={Logic.GetSpawnedEntities(bL)}for f=1,#nR do if Logic.IsLeader(nR[f])==1 then local nS={Logic.GetSoldiersAttachedToLeader(nR[f])}for aX=2,#nS do Logic.SetVisible(nS[aX],self.Visible)end else Logic.SetVisible(nR[f],self.Visible)end end else if Logic.IsLeader(bL)==1 then local nS={Logic.GetSoldiersAttachedToLeader(bL)}for aX=2,#nS do Logic.SetVisible(nS[aX],self.Visible)end else Logic.SetVisible(bL,self.Visible)end end end;function B_Reprisal_SetVisible:GetCustomData(b4)if b4==1 then return{"true","false"}end end;function B_Reprisal_SetVisible:Debug(b3)if not IsExisting(self.Entity)then error(b3.Identifier..": "..self.Name..": entity '"..self.Entity.."' does not exist!")return true end;return false end;RegisterBehavior(B_Reprisal_SetVisible)function Reprisal_SetVulnerability(...)return B_Reprisal_SetVulnerability:new(...)end;B_Reprisal_SetVulnerability={Name="Reprisal_SetVulnerability",Description={en="Reprisal: Changes the vulnerability of the entity. If the entity is a spawner the spawned entities will be affected.",de="Vergeltung: Macht eine Entity verwundbar oder unverwundbar. Handelt es sich um einen Spawner, sind die gespawnten Entities betroffen.",fr="Rétribution: rend une Entité vulnérable ou invulnérable. S'il s'agit d'un spawn, les Entities spawnées sont affectées."},Parameter={{ParameterType.ScriptName,en="Entity",de="Entity",fr="Entité"},{ParameterType.Custom,en="Vulnerability",de="Verwundbar",fr="Vulnérabilité"}}}function B_Reprisal_SetVulnerability:GetReprisalTable()return{Reprisal.Custom,{self,self.CustomFunction}}end;function B_Reprisal_SetVulnerability:AddParameter(b4,b5)if b4==0 then self.Entity=b5 elseif b4==1 then self.Vulnerability=ToBoolean(b5)end end;function B_Reprisal_SetVulnerability:CustomFunction(b3)if not IsExisting(self.Entity)then return end;local bL=GetID(self.Entity)local m9=Logic.GetEntityType(bL)local nQ=Logic.GetEntityTypeName(m9)local nT={bL}if string.find(nQ,"S_")or string.find(nQ,"B_NPC_Bandits")or string.find(nQ,"B_NPC_Barracks")then nT={Logic.GetSpawnedEntities(bL)}end;local nU="MakeInvulnerable"if self.Vulnerability then nU="MakeVulnerable"end;for f=1,#nT,1 do if Logic.IsLeader(nT[f])==1 then local aD={Logic.GetSoldiersAttachedToLeader(nT[f])}for aX=2,#aD,1 do _G[nU](aD[aX])end end;_G[nU](nT[f])end end;function B_Reprisal_SetVulnerability:GetCustomData(b4)if b4==1 then return{"true","false"}end end;function B_Reprisal_SetVulnerability:Debug(b3)if not IsExisting(self.Entity)then error(b3.Identifier..": "..self.Name..": entity '"..self.Entity.."' does not exist!")return true end;return false end;RegisterBehavior(B_Reprisal_SetVulnerability)function Reprisal_SetModel(...)return B_Reprisal_SetModel:new(...)end;B_Reprisal_SetModel={Name="Reprisal_SetModel",Description={en="Reprisal: Changes the model of the entity. Be careful, some models crash the game.",de="Vergeltung: Ändert das Model einer Entity. Achtung: Einige Modelle führen zum Absturz.",fr="Rétribution: modifie le modèle d'une entité. Attention: certains modèles entraînent un crash."},Parameter={{ParameterType.ScriptName,en="Entity",de="Entity",fr="Entité"},{ParameterType.Custom,en="Model",de="Model",fr="Modèle"}}}function B_Reprisal_SetModel:GetReprisalTable()return{Reprisal.Custom