Effects_E_Knight_Saraya_Aura")end;table.sort(b7)return b7 end end;function B_Reprisal_SetModel:Debug(b3)if not IsExisting(self.Entity)then error(b3.Identifier..": "..self.Name..": entity '"..self.Entity.."' does not exist!")return true end;if not Models[self.Model]then error(b3.Identifier..": "..self.Name..": model '"..self.Entity.."' does not exist!")return true end;return false end;RegisterBehavior(B_Reprisal_SetModel)function Reward_SetPosition(...)return B_Reward_SetPosition:new(...)end;B_Reward_SetPosition=CopyTable(B_Reprisal_SetPosition)B_Reward_SetPosition.Name="Reward_SetPosition"B_Reward_SetPosition.Description.en="Reward: Places an entity relative to the position of another. The entity can look the target."B_Reward_SetPosition.Description.de="Lohn: Setzt eine Entity relativ zur Position einer anderen. Die Entity kann zum Ziel ausgerichtet werden."B_Reward_SetPosition.Description.fr="Récompense: Définit une Entity vis-à-vis de la position d'une autre. L'entité peut être orientée vers la cible."B_Reward_SetPosition.GetReprisalTable=nil;B_Reward_SetPosition.GetRewardTable=function(self,b3)return{Reward.Custom,{self,self.CustomFunction}}end;RegisterBehavior(B_Reward_SetPosition)function Reward_ChangePlayer(...)return B_Reward_ChangePlayer:new(...)end;B_Reward_ChangePlayer=CopyTable(B_Reprisal_ChangePlayer)B_Reward_ChangePlayer.Name="Reward_ChangePlayer"B_Reward_ChangePlayer.Description.en="Reward: Changes the owner of the entity or a battalion."B_Reward_ChangePlayer.Description.de="Lohn: Ändert den Besitzer einer Entity oder eines Battalions."B_Reward_ChangePlayer.Description.fr="Récompense: Change le propriétaire d'une entité ou d'un bataillon."B_Reward_ChangePlayer.GetReprisalTable=nil;B_Reward_ChangePlayer.GetRewardTable=function(self,b3)return{Reward.Custom,{self,self.CustomFunction}}end;RegisterBehavior(B_Reward_ChangePlayer)function Reward_MoveToPosition(...)return B_Reward_MoveToPosition:new(...)end;B_Reward_MoveToPosition={Name="Reward_MoveToPosition",Description={en="Reward: Moves an entity relative to another entity. If angle is zero the entities will be standing directly face to face.",de="Lohn: Bewegt eine Entity relativ zur Position einer anderen. Wenn Winkel 0 ist, stehen sich die Entities direkt gegenüber.",fr="Récompense: Déplace une entité par rapport à la position d'une autre. Si l'angle est égal à 0, les entités sont directement opposées."},Parameter={{ParameterType.ScriptName,en="Settler",de="Siedler",fr="Settler"},{ParameterType.ScriptName,en="Destination",de="Ziel",fr="Destination"},{ParameterType.Number,en="Distance",de="Entfernung",fr="Distance"},{ParameterType.Number,en="Angle",de="Winkel",fr="Angle"}}}function B_Reward_MoveToPosition:GetRewardTable()return{Reward.Custom,{self,self.CustomFunction}}end;function B_Reward_MoveToPosition:AddParameter(b4,b5)if b4==0 then self.Entity=b5 elseif b4==1 then self.Target=b5 elseif b4==2 then self.Distance=b5*1 elseif b4==3 then self.Angle=b5*1 end end;function B_Reward_MoveToPosition:CustomFunction(b3)if not IsExisting(self.Entity)or not IsExisting(self.Target)then return end;self.Angle=self.Angle or 0;local c0=GetID(self.Entity)local nO=GetID(self.Target)local aK=Logic.GetEntityOrientation(nO)local C,D,E=Logic.EntityGetPos(nO)if Logic.IsBuilding(nO)==1 then C,D=Logic.GetBuildingApproachPosition(nO)aK=aK-90 end;C=C+self.Distance*math.cos(math.rad(aK+self.Angle))D=D+self.Distance*math.sin(math.rad(aK+self.Angle))Logic.MoveSettler(c0,C,D)self.EntityMovingJob=RequestJob(function(nV,nW)if Logic.IsEntityMoving(nV)==false then LookAt(nV,nW)return true end end,c0,nO)end;function B_Reward_MoveToPosition:Reset(b3)if self.EntityMovingJob then EndJob(self.EntityMovingJob)end end;function B_Reward_MoveToPosition:Debug(b3)if tonumber(self.Distance)==nil or self.Distance<50 then error(b3.Identifier..": "..self.Name..": Distance is nil or to short!")return true elseif not IsExisting(self.Entity)or not IsExisting(self.Target)then error(b3.Identifier..": "..self.Name..": Mover entity or target entity does not exist!")return true end;return false end;RegisterBehavior(B_Reward_MoveToPosition)function Reward_VictoryWithParty()return B_Reward_VictoryWithParty:new()end;B_Reward_VictoryWithParty={Name="Reward_VictoryWithParty",Description={en="Reward: (Singleplayer) The player wins the game with an animated festival on the market. Continue playing deleates the festival.",de="Lohn: (Einzelspieler) Der Spieler gewinnt das Spiel mit einer animierten Siegesfeier. Bei weiterspielen wird das Fest gelöscht.",fr="Récompense: (Joueur unique) Le joueur gagne la partie avec une fête de la victoire animée. Si le joueur continue à jouer, la fête est effacée."},Parameter={}}function B_Reward_VictoryWithParty:GetRewardTable()return{Reward.Custom,{self,self.CustomFunction}}end;function B_Reward_VictoryWithParty:AddParameter(b4,b5)end;function B_Reward_VictoryWithParty:CustomFunction(b3)if not Lib.QuestBehavior then return end;if Framework.IsNetworkGame()then error(b3.Identifier..": "..self.Name..": Can not be used in multiplayer!")return end;Victory(g_VictoryAndDefeatType.VictoryMissionComplete)local n=b3.ReceivingPlayer;local nX=Logic.GetMarketplace(n)if IsExisting(nX)then local aI=GetPosition(nX)Logic.CreateEffect(EGL_Effects.FXFireworks01,aI.X,aI.Y,0)Logic.CreateEffect(EGL_Effects.FXFireworks02,aI.X,aI.Y,0)local nY=self:GenerateParty(n)Lib.QuestBehavior.Global.VictoryWithPartyEntities[n]=nY;Logic.ExecuteInLuaLocalState(string.format([[
                local MarketID = %d
                if IsExisting(MarketID) then
                    CameraAnimation.AllowAbort = false
                    CameraAnimation.QueueAnimation(CameraAnimation.SetCameraToEntity, MarketID)
                    CameraAnimation.QueueAnimation(CameraAnimation.StartCameraRotation, 5)
                    CameraAnimation.QueueAnimation(CameraAnimation.Stay ,9999)
                end

                GUI_Window.ContinuePlayingClicked_Orig_Reward_VictoryWithParty = GUI_Window.ContinuePlayingClicked
                GUI_Window.ContinuePlayingClicked = function()
                    GUI_Window.ContinuePlayingClicked_Orig_Reward_VictoryWithParty()
                    
                    local PlayerID = GUI.GetPlayerID()
                    GUI.SendScriptCommand("B_Reward_VictoryWithParty:ClearParty(" ..PlayerID.. ")")

                    CameraAnimation.AllowAbort = true
                    CameraAnimation.Abort()
                end
            ]],nX))end end;function B_Reward_VictoryWithParty:ClearParty(ag)if Lib.QuestBehavior.Global.VictoryWithPartyEntities[ag]then for g,h in pairs(Lib.QuestBehavior.Global.VictoryWithPartyEntities[ag])do DestroyEntity(h)end;Lib.QuestBehavior.Global.VictoryWithPartyEntities[ag]=nil end end;function B_Reward_VictoryWithParty:GenerateParty(ag)local nZ={}local n_=Logic.GetMarketplace(ag)if n_~=nil and n_~=0 then local o0,o1=Logic.GetEntityPosition(n_)local al=Logic.CreateEntity(Entities.D_X_Garland,o0,o1,0,ag)table.insert(nZ,al)for aX=1,10 do for g=1,10 do local o2=o0-700+aX*150;local o3=o1-700+g*150;local o4=math.random(1,100)if o4>70 then local o5=GetRandomSettlerType()local Q=math.random(1,359)local o6=Logic.CreateEntityOnUnblockedLand(o5,o2,o3,Q,ag)Logic.SetTaskList(o6,TaskLists.TL_WORKER_FESTIVAL_APPLAUD_SPEECH)table.insert(nZ,o6)end end end end;return nZ end;function B_Reward_VictoryWithParty:Debug(b3)if Lib.QuestBehavior then if Lib.QuestBehavior.Global.VictoryWithPartyEntities[b3.ReceivingPlayer]then error(b3.Identifier..": "..self.Name..": Victory festival already started for player "..b3.ReceivingPlayer.."!")return true end end;return false end;RegisterBehavior(B_Reward_VictoryWithParty)function Reward_SetVisible(...)return B_Reward_SetVisible:new(...)end;B_Reward_SetVisible=CopyTable(B_Reprisal_SetVisible)B_Reward_SetVisible.Name="Reward_SetVisible"B_Reward_SetVisible.Description.en="Reward: Changes the visibility of an entity. If the entity is a spawner the spawned entities will be affected."B_Reward_SetVisible.Description.de="Lohn: Setzt die Sichtbarkeit einer Entity. Handelt es sich um einen Spawner werden auch die gespawnten Entities beeinflusst."B_Reward_SetVisible.Description.fr="Récompense: Définit la visibilité d'une Entity. S'il s'agit d'un spawn, les entités spawnées sont également influencées."B_Reward_SetVisible.GetReprisalTable=nil;B_Reward_SetVisible.GetRewardTable=function(self,b3)return{Reward.Custom,{self,self.CustomFunction}}end;Regis