,"R_Fish")and not string.find(g,"^[GEHUVXYZgt][ADSTfm]*")and not string.find(string.lower(g),"goods|tools_")then table.insert(b7,g)end end;table.insert(b7,"Effects_Dust01")table.insert(b7,"Effects_E_DestructionSmoke")table.insert(b7,"Effects_E_DustLarge")table.insert(b7,"Effects_E_DustSmall")table.insert(b7,"Effects_E_Firebreath")table.insert(b7,"Effects_E_Fireworks01")table.insert(b7,"Effects_E_Flies01")table.insert(b7,"Effects_E_Grasshopper03")table.insert(b7,"Effects_E_HealingFX")table.insert(b7,"Effects_E_Knight_Chivalry_Aura")table.insert(b7,"Effects_E_Knight_Plunder_Aura")table.insert(b7,"Effects_E_Knight_Song_Aura")table.insert(b7,"Effects_E_Knight_Trader_Aura")table.insert(b7,"Effects_E_Knight_Wisdom_Aura")table.insert(b7,"Effects_E_KnightFight")table.insert(b7,"Effects_E_NA_BlowingSand01")table.insert(b7,"Effects_E_NE_BlowingSnow01")table.insert(b7,"Effects_E_Oillamp")table.insert(b7,"Effects_E_SickBuilding")table.insert(b7,"Effects_E_Splash")table.insert(b7,"Effects_E_Torch")table.insert(b7,"Effects_Fire01")table.insert(b7,"Effects_FX_Lantern")table.insert(b7,"Effects_FX_SmokeBIG")table.insert(b7,"Effects_XF_BuildingSmoke")table.insert(b7,"Effects_XF_BuildingSmokeLarge")table.insert(b7,"Effects_XF_BuildingSmokeMedium")table.insert(b7,"Effects_XF_HouseFire")table.insert(b7,"Effects_XF_HouseFireLo")table.insert(b7,"Effects_XF_HouseFireMedium")table.insert(b7,"Effects_XF_HouseFireSmall")if g_GameExtraNo>0 then table.insert(b7,"Effects_E_KhanaTemple_Fire")table.insert(b7,"Effects_E_Knight_Saraya_Aura")end;table.sort(b7)return b7 end;function Lib.QuestBehavior.Global:OnThiefInfiltratedBuilding(lG,ag,hZ,lJ)for f=1,Quests[0]do if Quests[f]and Quests[f].State==QuestState.Active and Quests[f].ReceivingPlayer==ag then for aX=1,Quests[f].Objectives[0]do if Quests[f].Objectives[aX].Type==Objective.Custom2 then if Quests[f].Objectives[aX].Data[1].Name=="Goal_SpyOnBuilding"then if GetID(Quests[f].Objectives[aX].Data[1].Building)==hZ then Quests[f].Objectives[aX].Data[1].Infiltrated=true;if Quests[f].Objectives[aX].Data[1].Delete then DestroyEntity(lG)end end elseif Quests[f].Objectives[aX].Data[1].Name=="Goal_StealFromBuilding"then local bP;local nK=Logic.GetEntityType(hZ)==Entities.B_Cistern;local nI=Logic.IsEntityInCategory(hZ,EntityCategories.Cathedrals)==1;local nJ=Logic.GetEntityType(hZ)==Entities.B_StoreHouse;if nJ or nI or nK then Quests[f].Objectives[aX].Data[1].SuccessfullyStohlen=true else for g=1,#Quests[f].Objectives[aX].Data[1].RobberList do local oc=Quests[f].Objectives[aX].Data[1].RobberList[g]if oc[1]==hZ and oc[2]==lG then bP=true;break end end end;if not bP then table.insert(Quests[f].Objectives[aX].Data[1].RobberList,{hZ,lG})end end end end end end end;function Lib.QuestBehavior.Global:OnThiefDeliverEarnings(lG,ag,hZ,lJ,od)for f=1,Quests[0]do if Quests[f]and Quests[f].State==QuestState.Active and Quests[f].ReceivingPlayer==ag then for aX=1,Quests[f].Objectives[0]do if Quests[f].Objectives[aX].Type==Objective.Custom2 then if Quests[f].Objectives[aX].Data[1].Name=="Goal_StealFromBuilding"then for g=1,#Quests[f].Objectives[aX].Data[1].RobberList do local oc=Quests[f].Objectives[aX].Data[1].RobberList[g]if oc[1]==GetID(Quests[f].Objectives[aX].Data[1].Building)and oc[2]==lG then Quests[f].Objectives[aX].Data[1].SuccessfullyStohlen=true;break end end elseif Quests[f].Objectives[aX].Data[1].Name=="Goal_StealGold"then local oe=Quests[f].Objectives[aX].Data[1]if oe.Target==-1 or oe.Target==lJ then Quests[f].Objectives[aX].Data[1].StohlenGold=Quests[f].Objectives[aX].Data[1].StohlenGold+od;if oe.Printout then AddNote(string.format("%d/%d %s",oe.StohlenGold,oe.Amount,Localize({de="Talern gestohlen",en="gold stolen"})))end end end end end end end end;function Lib.QuestBehavior.Global:OnEntityKilled(of,og,oh,oi)if og~=0 and oi~=0 then self.SoldierKillsCounter[oi][og]=self.SoldierKillsCounter[oi][og]or 0;if Logic.IsEntityInCategory(of,EntityCategories.Soldier)==1 then self.SoldierKillsCounter[oi][og]=self.SoldierKillsCounter[oi][og]+1 end end end;function Lib.QuestBehavior.Global:GetEnemySoldierKillsOfPlayer(m1,m3)return self.SoldierKillsCounter[m1][m3]or 0 end;function Lib.QuestBehavior.Local:Initialize()if not self.IsInstalled then Lib.QuestBehavior.Global=nil end;self.IsInstalled=true end;function Lib.QuestBehavior.Local:OnSaveGameLoaded()end;function Lib.QuestBehavior.Local:OnReportReceived(aG,...)if aG==Report.LoadingFinished then self.LoadscreenClosed=true end end;RegisterModule(Lib.QuestBehavior.Name)Lib.Require("comfort/IsLocalScript")Lib.Register("module/quest/QuestJornal_API")function ShowJournalForQuest(b3,dT)assert(not IsLocalScript(),"Can not be used in local script!")local as=Quests[GetQuestID(b3)]if as then as.QuestNotes=dT==true end end;function AllowNotesForQuest(b3,dT)assert(not IsLocalScript(),"Can not be used in local script!")local as=Quests[GetQuestID(b3)]if as then Lib.QuestJornal.Global.CustomInputAllowed[b3]=dT==true end end;function CreateJournalEntry(du)assert(not IsLocalScript(),"Can not be used in local script!")du=du:gsub("{@[A-Za-z0-9:,]+}","")du=du:gsub("{[A-Za-z0-9_]+}","")return Lib.QuestJornal.Global:CreateJournalEntry(du,0,false)end;function AlterJournalEntry(aG,du)assert(not IsLocalScript(),"Can not be used in local script!")du=du:gsub("{@[A-Za-z0-9:,]+}","")du=du:gsub("{[A-Za-z0-9_]+}","")local jd=Lib.QuestJornal.Global:GetJournalEntry(aG)if jd then Lib.QuestJornal.Global:UpdateJournalEntry(aG,du,jd.Rank,jd.AlwaysVisible,jd.Deleted)end end;function HighlightJournalEntry(aG,oj)assert(not IsLocalScript(),"Can not be used in local script!")local jd=Lib.QuestJornal.Global:GetJournalEntry(aG)if jd then Lib.QuestJornal.Global:UpdateJournalEntry(aG,jd[1],oj==true and 1 or 0,jd.AlwaysVisible,jd.Deleted)end end;function DeleteJournalEntry(aG)assert(not IsLocalScript(),"Can not be used in local script!")local jd=Lib.QuestJornal.Global:GetJournalEntry(aG)if jd then Lib.QuestJornal.Global:UpdateJournalEntry(aG,jd[1],jd.Rank,jd.AlwaysVisible,true)end end;functi