losed then self:ProcessChatInput(arg[1],arg[2])elseif aG==Report.QuestJournalPlayerNote then self.InputShown[arg[1]]=arg[2]SendReportToLocal(Report.QuestJournalPlayerNote,arg[1],arg[2],arg[3]==true)elseif aG==Report.QuestJournalDisplayed then SendReportToLocal(Report.QuestJournalDisplayed,arg[1],arg[2],arg[3],arg[4])end end;function Lib.QuestJornal.Global:DisplayJournal(dx,ag)local ok=self.CustomInputAllowed[dx]==true;local ol=self:FormatJournalEntry(dx,ag)SendReport(Report.QuestJournalDisplayed,ag,dx,ol,ok)end;function Lib.QuestJornal.Global:CreateJournalEntry(du,om,on)self.Journal.ID=self.Journal.ID+1;table.insert(self.Journal,{ID=self.Journal.ID,AlwaysVisible=on==true,Quests={},Rank=om,du})return self.Journal.ID end;function Lib.QuestJornal.Global:GetJournalEntry(aG)for f=1,#self.Journal do if self.Journal[f].ID==aG then return self.Journal[f]end end end;function Lib.QuestJornal.Global:UpdateJournalEntry(aG,du,om,on,oo)for f=1,#self.Journal do if self.Journal[f].ID==aG then self.Journal[f].AlwaysVisible=on==true;self.Journal[f].Deleted=oo==true;self.Journal[f].Rank=om;self.Journal[f][1]=self.Journal[f][1]or du end end end;function Lib.QuestJornal.Global:AssociateJournalEntryWithQuest(aG,b3,dT)for f=1,#self.Journal do if self.Journal[f].ID==aG then self.Journal[f].Quests[b3]=dT==true end end end;function Lib.QuestJornal.Global:FormatJournalEntry(dx,ag)local as=Quests[GetQuestID(dx)]if as and as.QuestNotes and as.ReceivingPlayer==ag then local op=self:GetJournalEntriesSorted()local oq=false;local os=false;local np=""local g0=""for f=1,#op,1 do if op[f].AlwaysVisible or op[f].Quests[dx]then if not op[f].Deleted then local bd=ConvertPlaceholders(Localize(op[f][1]))if op[f].Rank==1 then bd="{scarlet}"..bd..self.TextColor;oq=true end;if op[f].Rank==0 then if oq then oq=false;bd="{cr}----------{cr}{cr}"..bd end;os=true end;if op[f].Rank==-1 then if os then os=false;g0="{violet}"bd="{cr}----------{cr}{cr}"..bd end;bd=g0 ..bd..self.TextColor end;np=np..(np~=""and"{cr}"or"