tion/HireEntertainer")if Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.Soldier)==1 then oT=GetStringText("UI_ObjectNames/HireMercenaries")oU=GetStringText("UI_ObjectDescription/HireMercenaries")elseif Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.CattlePasture)==1 then oT=GetStringText("UI_ObjectNames/G_Cow")oU=GetStringText("UI_ObjectDescription/G_Sheep")elseif Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.SheepPasture)==1 then oT=GetStringText("UI_ObjectNames/G_Sheep")oU=GetStringText("UI_ObjectDescription/G_Sheep")elseif Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.HeavyWeapon)==1 then oT=GetStringText("Names/"..cH)local T=GetSiegeengineTypeByCartType(b7.GoodType)local oV=Logic.GetEntityTypeName(T)oU=GetStringText("UI_ObjectDescription/Abilities_"..oV)end end;local oW=""if b7.Amount>1 then oW=string.format(" (%d/%d)",b7.Current,b7.Amount)end;local oX=""if KeyOf(b7.GoodType,Goods)~=nil then oX=string.format(Localize(Lib.Warehouse.Text.OfferTitle[2]),b7.GoodAmount,oT,oW)elseif KeyOf(b7.GoodType,Entities)~=nil then if Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.Military)==1 then oX=string.format(Localize(Lib.Warehouse.Text.OfferTitle[4]),oT,oW)elseif Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.SiegeEngine)==1 then oX=string.format(Localize(Lib.Warehouse.Text.OfferTitle[5]),oT,oW)elseif Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.CattlePasture)==1 or Logic.IsEntityTypeInCategory(b7.GoodType,EntityCategories.SheepPasture)==1 then oX=string.format(Localize(Lib.Warehouse.Text.OfferTitle[5]),oT,oW)else oX=string.format(Localize(Lib.Warehouse.Text.OfferTitle[3]),oT)end end;SetTooltipCosts(oX,oU,nil,{b7.PaymentType,oR},oS)end;function Lib.Warehouse.Local:WarehouseButtonUpdate(kp,gf,an)local aP=Logic.GetEntityName(an)local c6,cM=string.find(aP,"_Post")aP=string.sub(aP,1,c6-1)local ar=self:GetIndex(aP)if ar==0 then XGUIEng.ShowWidget(gf,0)return end;local bX=self:GetActivOffers(aP)loca