9,DeathTimer=90},Consume={FoodFactor=0.0012,ClothesFactor=0.0006,BeerFactor=0.0012,HygieneFactor=0.0006,Progression=35000},SuspendedSettlers={MourningTime=5*60}}Lib.Require("comfort/GetPredatorSpawnerTypes")Lib.Require("comfort/GetHealth")Lib.Require("comfort/SetHealth")Lib.Require("core/Core")Lib.Require("module/city/Construction")Lib.Require("module/ui/UIBuilding")Lib.Require("module/ui/UITools")Lib.Require("module/mode/SettlementSurvival_API")Lib.Require("module/mode/SettlementSurvival_Text")Lib.Register("module/mode/SettlementSurvival")function Lib.SettlementSurvival.Global:Initialize()if not self.IsInstalled then Report.FireAlarmDeactivated_Internal=CreateReport("Event_FireAlarmDeactivated_Internal")Report.FireAlarmActivated_Internal=CreateReport("Event_FireAlarmActivated_Internal")Report.RepairAlarmDeactivated_Internal=CreateReport("Event_RepairAlarmFeactivated")Report.ReRepairAlarmActivated_Internal=CreateReport("Event_ReRepairAlarmActivated_Internal")Report.AnimalDiedFromIllness=CreateReport("Event_AnimalDiedFromIllness")Report.SettlerDiedFromStarvation=CreateReport("Event_SettlerDiedFromStarvation")Report.SettlerDiedFromIllness=CreateReport("Event_SettlerDiedFromIllness")for n=1,8 do self.AnimalPlague[n]={}self.ColdWeather[n]={Consumption=0}self.Famine[n]={}self.Negligence[n]={}self.Plague[n]={}self.Consume[n]={Buildings={}}self.SuspendedSettlers[n]={}end;RequestJobByEventType(Events.LOGIC_EVENT_EVERY_TURN,function()local p1=Logic.GetCurrentTurn()Lib.SettlementSurvival.Global:ResumeSettlersAfterMourning(p1)Lib.SettlementSurvival.Global:ControlSettlersBaseConsumption(p1)Lib.SettlementSurvival.Global:ControlSettlersBecomeIllDueToNegligence(p1)Lib.SettlementSurvival.Global:ControlBuildingsDuringHotWeather(p1)Lib.SettlementSurvival.Global:ControlBuildingsDuringColdWeather(p1)Lib.SettlementSurvival.Global:ControlSettlersSuccumToFamine(p1)Lib.SettlementSurvival.Global:ControlAnimalInfections(p1)Lib.SettlementSurvival.Global:ControlAnimalCorpsesDecay(p1)Lib.Settle