mp,0)}if#p6>0 then return false end end end end end;return true end end;function Lib.SettlementSurvival.Global:ControlSettlersBaseConsumption(p7)local n=p7%10;if self.IsActive and self.Consume.IsActive and n>=1 and n<=8 then if self.Consume.AffectAI or Logic.PlayerGetIsHumanFlag(n)then local p8={Logic.GetPlayerEntitiesInCategory(n,EntityCategories.OuterRimBuilding)}local p9={Logic.GetPlayerEntitiesInCategory(n,EntityCategories.CityBuilding)}local pa=Array_Append(p8,p9)for f=1,#pa do local jT=pa[f]if not self.Consume[n].Buildings[jT]then self.Consume[n].Buildings[jT]={0.8,0.8,0.8,0.8}end;local pb=Logic.IsBuildingStopped(jT)==true;local pc=Logic.IsEntityInCategory(jT,EntityCategories.OuterRimBuilding)==1;local pd=self:GetEffectiveWorkerInBuilding(jT)local pe=self:CalculateDistanceFactor(jT)if Logic.IsNeedActive(jT,Needs.Nutrition)then local mT=Lib.SettlementSurvival.Shared.Consume.FoodFactor;mT=pb and mT*0.50 or mT;mT=pc and mT*0.50 or mT;mT=mT*pe;local pf=self.Consume[n].Buildings[jT][1]local pg=mT*pd;if self:IsAnyOtherNeedCritical(jT,Needs.Nutrition)then pg=0 end;local k8=math.max(pf-pg,0)local ph=Logic.GetNeedState(jT,Needs.Nutrition)if ph-k8>0.1 then k8=ph>0.8 and ph or 0.8 end;self.Consume[n].Buildings[jT][1]=k8;Logic.SetNeedState(jT,Needs.Nutrition,k8)end;if Logic.IsNeedActive(jT,Needs.Clothes)then local mT=Lib.SettlementSurvival.Shared.Consume.ClothesFactor;mT=pb and mT*0.50 or mT;mT=pc and mT*0.25 or mT;mT=mT*pe;local pf=self.Consume[n].Buildings[jT][2]local pg=mT*pd;if self:IsAnyOtherNeedCritical(jT,Needs.Clothes)then pg=0 end;local k8=math.max(pf-pg,0)local ph=Logic.GetNeedState(jT,Needs.Clothes)if ph-k8>0.1 then k8=ph>0.8 and ph or 0.8 end;self.Consume[n].Buildings[jT][2]=k8;Logic.SetNeedState(jT,Needs.Clothes,k8)end;if Logic.IsNeedActive(jT,Needs.Hygiene)then local mT=Lib.SettlementSurvival.Shared.Consume.HygieneFactor;mT=pb and mT*0.50 or mT;mT=pc and mT*0.25 or mT;mT=mT*pe;local pf=self.Consume[n].Buildings[jT][3]local pg=mT*pd;if self:IsAnyOtherNeedCrit