 bu>0 then self.FestivalStarted=true;self.FestivalCounter=self.FestivalCounter and self.FestivalCounter+1 or 1;if self.FestivalCounter>=self.NeededFestivals then self.FestivalCounter=nil;return true end elseif bu==0 then self.FestivalStarted=false end end;function B_Goal_Festivals:Debug(b3)if Logic.GetStoreHouse(self.PlayerID)==0 then debug(false,b3.Identifier..": "..self.Name..": Player "..self.PlayerID.." is dead :-(")return true elseif GetPlayerCategoryType(self.PlayerID)~=PlayerCategories.City then debug(false,b3.Identifier..": "..self.Name..":  Player "..self.PlayerID.." is no city")return true elseif self.NeededFestivals<0 then debug(false,b3.Identifier..": "..self.Name..": Number of Festivals is negative")return true end;return false end;function B_Goal_Festivals:Reset()self.FestivalCounter=nil;self.FestivalStarted=nil end;function B_Goal_Festivals:GetIcon()return{4,15}end;RegisterBehavior(B_Goal_Festivals)function Goal_Capture(...)return B_Goal_Capture:new(...)end;B_Goal_Capture={Name="Goal_Capture",Description={en="Goal: Capture a cart.",de="Ziel: Ein Karren muss erobert werden.",fr="Objectif: un chariot doit être conquis."},Parameter={{ParameterType.ScriptName,en="Script name",de="Skriptname",fr="Nom de l'entité"}}}function B_Goal_Capture:GetGoalTable()return{Objective.Capture,1,{self.ScriptName}}end;function B_Goal_Capture:AddParameter(b4,b5)if b4==0 then self.ScriptName=b5 end end;function B_Goal_Capture:GetMsgKey()local al=GetID(self.ScriptName)if Logic.IsEntityAlive(al)then al=Logic.GetEntityType(al)if al and al~=0 then if Logic.IsEntityTypeInCategory(al,EntityCategories.AttackableMerchant)==1 then return"Quest_Capture_Cart"elseif Logic.IsEntityTypeInCategory(al,EntityCategories.SiegeEngine)==1 then return"Quest_Capture_SiegeEngine"elseif Logic.IsEntityTypeInCategory(al,EntityCategories.Worker)==1 or Logic.IsEntityTypeInCategory(al,EntityCategories.Spouse)==1 or Logic.IsEntityTypeInCategory(al,EntityCategories.Hero)==1 then return"Quest_Capture_VIPOfPl