ew(...)end;B_Goal_ResourceAmount={Name="Goal_ResourceAmount",Description={en="Goal: Reach a specified amount of resources in a doodad",de="Ziel: In einer Mine soll weniger oder mehr als eine angegebene Anzahl an Rohstoffen sein.",fr="Objectif: Dans une mine, il doit y avoir moins ou plus de matières premières qu'un nombre indiqué."},Parameter={{ParameterType.ScriptName,en="Script name",de="Skriptname",fr="Nom de l'entité"},{ParameterType.Custom,en="Relation",de="Relation",fr="Relation"},{ParameterType.Number,en="Amount",de="Menge",fr="Quantité"}}}function B_Goal_ResourceAmount:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_ResourceAmount:AddParameter(b4,b5)if b4==0 then self.ScriptName=b5 elseif b4==1 then self.bRelSmallerThan=b5=="<"elseif b4==2 then self.Amount=b5*1 end end;function B_Goal_ResourceAmount:CustomFunction(b3)local al=GetID(self.ScriptName)if al and al~=0 and Logic.GetResourceDoodadGoodType(al)~=0 then local bx=Logic.GetResourceDoodadGoodAmount(al)if self.bRelSmallerThan and bx<self.Amount or not self.bRelSmallerThan and bx>=self.Amount then return true end end;return nil end;function B_Goal_ResourceAmount:GetCustomData(b4)local b7={}if b4==1 then table.insert(b7,">=")table.insert(b7,"<")else assert(false)end;return b7 end;function B_Goal_ResourceAmount:Debug(b3)if not IsExisting(self.ScriptName)then debug(false,b3.Identifier..": "..self.Name..": entity '"..self.ScriptName.."' does not exist!")return true elseif tonumber(self.Amount)==nil or self.Amount<0 then debug(false,b3.Identifier..": "..self.Name..": error at amount! (nil or below 0)")return true end;return false end;RegisterBehavior(B_Goal_ResourceAmount)function Goal_InstantFailure()return B_Goal_InstantFailure:new()end;B_Goal_InstantFailure={Name="Goal_InstantFailure",Description={en="Goal: Instant failure, the goal returns false.",de="Ziel: Direkter Misserfolg, das Goal sendet false.",fr="Objectif: échec direct, le goal envoie false."}}function B_Goal_I