L,Goods[self.SecondCostType],self.SecondCostAmount)end;Logic.InteractiveObjectSetAvailability(bL,true)if self.UsingState then for f=1,8 do Logic.InteractiveObjectSetPlayerState(bL,f,self.UsingState)end end;Logic.InteractiveObjectSetRewardResourceCartType(bL,Entities.U_ResourceMerchant)Logic.InteractiveObjectSetRewardGoldCartType(bL,Entities.U_GoldCart)Logic.InteractiveObjectSetCostResourceCartType(bL,Entities.U_ResourceMerchant)Logic.InteractiveObjectSetCostGoldCartType(bL,Entities.U_GoldCart)RemoveInteractiveObjectFromOpenedList(bL)table.insert(HiddenTreasures,bL)end;function B_Reward_ObjectInit:GetCustomData(b4)if b4==3 or b4==5 or b4==7 then local b7={"-","G_Beer","G_Bread","G_Broom","G_Carcass","G_Cheese","G_Clothes","G_Dye","G_Gold","G_Grain","G_Herb","G_Honeycomb","G_Iron","G_Leather","G_Medicine","G_Milk","G_RawFish","G_Salt","G_Sausage","G_SmokedFish","G_Soap","G_Stone","G_Water","G_Wood","G_Wool"}if g_GameExtraNo>=1 then b7[#b7+1]="G_Gems"b7[#b7+1]="G_MusicalInstrument"b7[#b7+1]="G_Olibanum"end;return b7 elseif b4==9 then return{"-","Knight only","Always","Never"}end end;function B_Reward_ObjectInit:Debug(b3)if Logic.IsInteractiveObject(GetID(self.ScriptName))==false then debug(false,b3.Identifier..": "..self.Name..": '"..self.ScriptName.."' is not a interactive object!")return true end;if self.UsingState~=1 and self.Distance<50 then warn(false,b3.Identifier..": "..self.Name..": distance is maybe too short!")end;if self.Waittime<0 then debug(false,b3.Identifier..": "..self.Name..": waittime must be equal or greater than 0!")return true end;if self.RewardType and self.RewardType~="-"then if not Goods[self.RewardType]then debug(false,b3.Identifier..": "..self.Name..": '"..self.RewardType.."' is invalid good type!")return true elseif self.RewardAmount<1 then debug(false,b3.Identifier..": "..self.Name..": amount can not be 0 or negative!")return true end end;if self.FirstCostType and self.FirstCostType~="-"then if not Goods[self.FirstCostType]then debug(false,b