 indiqué dans un engin de guerre."},Parameter={{ParameterType.ScriptName,en="Script name",de="Skriptname",fr="Nom de l'entité"},{ParameterType.Custom,en="Relation",de="Relation",fr="Relation"},{ParameterType.Number,en="Amount",de="Menge",fr="Quantité"}}}function B_Goal_AmmunitionAmount:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_AmmunitionAmount:AddParameter(b4,b5)if b4==0 then self.Scriptname=b5 elseif b4==1 then self.bRelSmallerThan=tostring(b5)=="true"or b5=="<"elseif b4==2 then self.Amount=b5*1 end end;function B_Goal_AmmunitionAmount:CustomFunction()local u=GetID(self.Scriptname)if not IsExisting(u)then return false end;local bx=Logic.GetAmmunitionAmount(u)if self.bRelSmallerThan and bx<self.Amount or not self.bRelSmallerThan and bx>=self.Amount then return true end;return nil end;function B_Goal_AmmunitionAmount:Debug(b3)if self.Amount<0 then error(b3.Identifier..": "..self.Name..": Amount is negative")return true end end;function B_Goal_AmmunitionAmount:GetCustomData(b4)if b4==1 then return{"<",">="}end end;RegisterBehavior(B_Goal_AmmunitionAmount)function Goal_CityReputation(...)return B_Goal_CityReputation:new(...)end;B_Goal_CityReputation={Name="Goal_CityReputation",Description={en="Goal: The reputation of the quest receivers city must at least reach the desired hight.",de="Ziel: Der Ruf der Stadt des Empfängers muss mindestens so hoch sein, wie angegeben.",fr="Objectif: la réputation de la ville du receveur doit être au moins aussi élevée que celle indiquée."},Parameter={{ParameterType.Number,en="City reputation",de="Ruf der Stadt",fr="Réputation de la ville"}},Text={de="RUF DER STADT{cr}{cr}Hebe den Ruf der Stadt durch weise Herrschaft an!{cr}Benötigter Ruf: %d",en="CITY REPUTATION{cr}{cr}Raise your reputation by fair rulership!{cr}Needed reputation: %d",fr="RÉPUTATION DE LA VILLE{cr}{cr} Augmente la réputation de la ville en la gouvernant sagement!{cr}Réputation requise : %d"}}function B_Goal_CityReputation:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_CityReputation:AddParameter(b4,b5)if b4==0 then self.Reputation=b5*1 end end;function B_Goal_CityReputation:CustomFunction(b3)self:SetCaption(b3)local nE=Logic.GetCityReputation(b3.ReceivingPlayer)*100;if nE>=self.Reputation then return true end end;function B_Goal_CityReputation:SetCaption(b3)if not b3.QuestDescription or b3.QuestDescription==""then local bd=string.format(Localize(self.Text),self.Reputation)Lib.Core.Quest:ChangeCustomQuestCaptionText(bd.."%",b3)end end;function B_Goal_CityReputation:GetIcon()return{5,14}end;function B_Goal_CityReputation:Debug(b3)if type(self.Reputation)~="number"or self.Reputation<0 or self.Reputation>100 then error(b3.Identifier..": "..self.Name..": Reputation must be between 0 and 100!")return true end;return false end;RegisterBehavior(B_Goal_CityReputation)function Goal_DestroySpawnedEntities(...)return B_Goal_DestroySpawnedEntities:new(...)end;B_Goal_DestroySpawnedEntities={Name="Goal_DestroySpawnedEntities",Description={en="Goal: Destroy all entities spawned at the spawnpoint.",de="Ziel: Zerstöre alle Entitäten, die bei dem Spawnpoint erzeugt wurde.",fr="Objectif: Détruire toutes les entités créées au point d'apparition."},Parameter={{ParameterType.ScriptName,en="Spawnpoint",de="Spawnpoint",fr="Point d'émergence"},{ParameterType.Number,en="Amount",de="Menge",fr="Quantité"},{ParameterType.Custom,en="Name is prefixed",de="Name ist Präfix",fr="Le nom est un préfixe"}}}function B_Goal_DestroySpawnedEntities:GetGoalTable()if self.Prefixed then local d4=table.remove(self.SpawnPoint)local f=1;while IsExisting(d4 ..f)do table.insert(self.SpawnPoint,d4 ..f)f=f+1 end;assert(#self.SpawnPoint>0,"No spawnpoints found!")end;return{Objective.DestroyEntities,3,self.SpawnPoint,self.Amount}end;function B_Goal_DestroySpawnedEntities:AddParameter(b4,b5)if b4==0 then self.SpawnPoint={b5}elseif b4==1 then self.Amount=b5*1 elseif b4==2 then b5=b5 or"false"self.Prefixed=ToBoolean(b5)end end;function B_Goal_DestroySpawnedEntities:GetMsgKey()local al=GetID(self.SpawnPoint[1])if al~=0 then local fF=Logic.GetEntityTypeName(Logic.GetEntityType(al))if Logic.IsEntityTypeInCategory(al,EntityCategories.AttackableBuilding)==1 then return"Quest_Destroy_Leader"elseif fF:find("Bear")or fF:find("Lion")or fF:find("Tiger")or fF:find("Wolf")then return"Quest_DestroyEntities_Predators"elseif fF:find("Military")or fF:find("Cart")then return"Quest_DestroyEntities_Unit"end end;return"Quest_DestroyEntities"end;function B_Goal_DestroySpawnedEntities:GetCustomData(b4)if b4==2 then return{"false","true"}end end;RegisterBehavior(B_Goal_DestroySpawnedEntities)function Goal_StealGold(...)return B_Goal_StealGold:new(...)end;B_Goal_StealGold={Name="Goal_StealGold",Description={en="Goal: Steal an explicit amount of gold from a players or any players city buildings.",de="Ziel: Diebe sollen eine bestimmte Menge Gold aus feindlichen Stadtgebäuden stehlen.",fr="Objectif: les voleurs doivent dérober une certaine quantité d'or dans les bâtiments urbains ennemis."},Parameter={{ParameterType.Number,en="Amount on Gold",de="Zu stehlende Menge",fr="Quantité à voler"},{ParameterType.Custom,en="Target player",de="Spieler von dem gestohlen wird",fr="Joueur à qui l'on vole"},{ParameterType.Custom,en="Cheat earnings",de="Einnahmen generieren",fr="Générer des revenus"},{ParameterType.Custom,en="Print progress",de="Fortschritt ausgeben",fr="Afficher les progrès"}}}function B_Goal_StealGold:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_StealGold:AddParameter(b4,b5)if b4==0 then self.Amount=b5*1 elseif b4==1 then local n=tonumber(b5)or-1;self.Target=n*1 elseif b4==2 then b5=b5 or"false"self.CheatEarnings=ToBoolean(b5)elseif b4==3 then b5=b5 or"true"self.Printout=ToBoolean(b5)end;self.StohlenGold=0 end;function B_Goal_StealGold:GetCustomData(b4)if b4==1 then return{"-",1,2,3,4,5,6,7,8}elseif b4==2 then return{"true","false"}end end;function B_Goal_StealGold:SetDescriptionOverwrite(b3)local nF=Localize({de=" anderen Spielern ",en=" different parties ",fr=" d'autres joueurs "})if self.Target~=-1 then nF=GetPlayerName(self.Target)if nF==nil or nF==""then nF=" PLAYER_NAME_MISSING "end end;if self.CheatEarnings then local nG={self.Target}if self.Target==-1 then nG={1,2,3,4,5,6,7,8}end;for f=1,#nG,1 do if f~=b3.ReceivingPlayer and Logic.GetStoreHouse(f)~=0 then local jP={Logic.GetPlayerEntitiesInCategory(f,EntityCategories.CityBuilding)}for aX=1,#jP,1 do local nH=Logic.GetBuildingProductEarnings(jP[aX])if nH<45 and Logic.GetTime()%5==0 then Logic.SetBuildingEarnings(jP[aX],nH+1)end end end end end;local bu=self.Amount-self.StohlenGold;bu=bu>0 and bu or 0;local gK={de="Gold von %s stehlen {cr}{cr}Aus Stadtgebäuden zu stehlende Goldmenge: %d",en="Steal gold from %s {cr}{cr}Amount on gold to steal from city buildings: %d",fr="Voler l'or de %s {cr}{cr}Quantité d'or à voler dans les bâtiments de la ville : %d"}return"{center}"..string.format(Localize(gK),nF,bu)end;function B_Goal_StealGold:CustomFunction(b3)if Lib.Core.Quest then Lib.Core.Quest:ChangeCustomQuestCaptionText(self:SetDescriptionOverwrite(b3),b3)end;if self.StohlenGold>=self.Amount then return true end;return nil end;function B_Goal_StealGold:GetIcon()return{5,13}end;function B_Goal_StealGold:Debug(b3)if tonumber(self.Amount)==nil and self.Amount<0 then error(b3.Identifier..": "..self.Name..": amount can not be negative!")return true end;return false end;function B_Goal_StealGold:Reset(b3)self.StohlenGold=0 end;RegisterBehavior(B_Goal_StealGold)function Goal_StealFromBuilding(...)return B_Goal_StealFromBuilding:new(...)end;B_Goal_StealFromBuilding={Name="Goal_StealFromBuilding",Description={en="Goal: The player has to steal from a building. Not a castle and not a village storehouse!",de="Ziel: Der Spieler muss ein bestimmtes Gebäude bestehlen. Dies darf keine Burg und kein Dorflagerhaus sein!",fr="Objectif: Le joueur doit voler un bâtiment spécifique. Il ne peut s'agir ni d'un château ni d'un entrepôt de village !"},Parameter={{ParameterType.ScriptName,en="Building",de="Gebäude",fr="Bâtiment"},{ParameterType.Custom,en="Cheat earnings",de="Einnahmen generieren",fr="Générer des revenus"}}}function B_Goal_StealFromBuilding:GetGoalTable()return{Objective.Custom2,{self,self.CustomFunction}}end;function B_Goal_StealFromBuilding:AddParameter(b4,b5)if b4==0 then self.Building=b5 elseif b4==1 then b5=b5 or"false"self.CheatEarnings=ToBoolean(b5)end;self.RobberList={}end;function B_Goal_StealFromBuilding:GetCustomData(b4)if b4==1 then return{"true","false"}end end;function B_Goal_StealFromBuilding:SetDescriptionOverwrite(b3)local nI=Logic.IsEntityInCategory(GetID(self.Building),EntityCategories.Cathedrals)==1;local nJ=Logic.GetEntityType(GetID(self.Building))==Entities.B_StoreHouse;local nK=Logic.GetEntityType(GetID(self.Building))==Entities.B_Cistern;local gK;if nI then gK={de="Sabotage {cr}{cr} Sendet einen Dieb und sabotiert die markierte Kirche.",en="Sabotage {cr}{cr} Send a thief to sabotage the marked chapel.",fr="Sabotage {cr}{cr} Envoyez un voleur pour saboter la chapelle marquée."}elseif nJ then gK={de="Lagerhaus bestehlen {cr}{cr} Sendet einen Dieb in das markierte Lagerhaus.",en="Steal from storehouse {cr}{cr} Steal from the marked storehouse.",fr="Voler un entrepôt {cr}{cr} Envoie un voleur dans l'entrepôt marqué."}elseif nK then gK={de="Sabotage {cr}{cr} Sendet einen Dieb und sabotiert den markierten Brunnen.",en="Sabotage {cr}{cr} Send a thief and break the marked well of the enemy.",fr="Sabotage {cr}{cr} Envoie un voleur et sabote le puits marqué."}else gK={de="Gebäude bestehlen {cr}{cr} Sendet einen Dieb und bestehlt das markierte Gebäude.",en="Steal from building {cr}{cr} Send a thief to steal from the marked building.",fr="Voler un bâtiment {cr}{cr} Envoie un voleur et vole le bâtiment marqué."}end;return"{center}"..Localize(gK)end;function B_Goal_StealFromBuilding:CustomFunction(b3)if not IsExisting(self.Building)then if self.Marker then Logic.DestroyEffect(self.Marker)end;return false end;if not self.Marker then local aI=GetPosition(self.Building)self.Marker=Logic.CreateEffect(EGL_Effects.E_Questmarker,aI.X,aI.Y,0)end;if self.CheatEarnings then local jT=GetID(self.Building)local nH=Logic.GetBuildingProductEarnings(jT)if Logic.IsEntityInCategory(jT,EntityCategories.CityBuilding)==1 and nH<45 and Logic.GetTime()%5==0 then Logic.SetBuildingEarnings(jT,nH+1)end end;if self.SuccessfullyStohlen then Logic.DestroyEffect(self.Marker)return true end;return nil end;function B_Goal_StealFromBuilding:GetIcon()return{5,13}end;function B_Goal_StealFromBuilding:Debug(b3)local nL=Logic.GetEntityTypeName(Logic.GetEntityType(GetID(self.Building)))local nM=Logic.IsEntityInCategory(GetID(self.Building),EntityCategories.Headquarters)==1;if Logic.IsBuilding(GetID(self.Building))==0 then error(b3.Identifier..": "..self.Name..": target is not a building")return true elseif not IsExisting(self.Building)then error(b3.Identifier..": "..self.Name..": target is destroyed :(")return true elseif string.find(nL,"B_NPC_BanditsHQ")or string.find(nL,"B_NPC_Cloister")or string.find(nL,"B_NPC_StoreHouse")then error(b3.Identifier..": "..self.Name..": village storehouses are not allowed!")return true elseif nM then error(b3.Identifier..": "..self.Name..": use Goal_StealInformation for headquarters!")return true end;return false end;function B_Goal_StealFromBuilding:Reset(b3)self.SuccessfullyStohlen=false;self.RobberList={}self.Marker=nil end;function B_Goal_StealFromBuilding:Interrupt(b3)Logic.DestroyEffect(self.Marker)end;RegisterBehavior(B_Goal_StealFromBuilding)function Goal_SpyOnBuilding(...)return B_Goal_SpyOnBuilding:new(...)end;B_Goal_SpyOnBuilding={Name="Goal_SpyOnBuilding",IconOverwrite={5,13},Description={en="Goal: Infiltrate a building with a thief. A thief must be able to steal from the target building.",de="Ziel: Infiltriere ein Gebäude mit einem Dieb. Nur mit Gebaueden möglich, die besto